window.PEPP_DATA = {"manifest":{"id":"pepp","title":"PEPP — Pediatric Education for Prehospital Professionals","subtitle":"The Ultimate Provider Course Reviewer","version":"1.0.0","edition":"Based on the AAP PEPP, 4th Edition","description":"A comprehensive, self-contained study reviewer for Pediatric Education for Prehospital Professionals. Each chapter includes a concise summary, clinical pearls, red flags, common mistakes, memory aids, decision trees, high-yield flashcards, PEPP-style quiz questions, and realistic pediatric scenarios. Built around the Pediatric Assessment Triangle, spanning both BLS- and ALS-level prehospital pediatric care, for EMTs, AEMTs, paramedics, and other prehospital providers.","icon":"baby","color":"#2ea043","accentColor":"#e06090","estimatedHours":14,"difficulty":"Beginner to Advanced","certification":"AAP PEPP Provider (BLS or ALS track)","examLink":"https://www.aap.org/en/pedialink/pediatric-education-for-prehospital-professionals/","audience":["EMT","AEMT","Paramedic","EMS Student"],"prerequisites":["Current BLS provider competency","PALS knowledge helpful but not required"],"contentTypes":["summary","flashcards","quizzes","scenarios","algorithms","tables"],"chapters":[{"id":"c01","number":1,"title":"Why Children Are Different: Developmental & Anatomic Considerations","section":"Foundations","difficulty":"Beginner"},{"id":"c02","number":2,"title":"The Pediatric Assessment Triangle","section":"Foundations","difficulty":"Beginner"},{"id":"c03","number":3,"title":"Primary Assessment (ABCDE) & Scene Size-Up","section":"Foundations","difficulty":"Intermediate"},{"id":"c04","number":4,"title":"History Taking, Secondary Assessment & Family-Centered Communication","section":"Foundations","difficulty":"Intermediate"},{"id":"c05","number":5,"title":"Respiratory Distress & Respiratory Failure","section":"Respiratory","difficulty":"Intermediate"},{"id":"c06","number":6,"title":"Shock Recognition & Field Management","section":"Circulation","difficulty":"Intermediate"},{"id":"c07","number":7,"title":"Cardiac Emergencies & Rhythm Recognition","section":"Circulation","difficulty":"Intermediate"},{"id":"c08","number":8,"title":"Neurologic Emergencies: Altered Mental Status & Seizures","section":"Neurologic","difficulty":"Intermediate"},{"id":"c09","number":9,"title":"Trauma: Assessment & Field Stabilization","section":"Trauma","difficulty":"Advanced"},{"id":"c10","number":10,"title":"Toxic Exposures & Environmental Emergencies","section":"Medical","difficulty":"Intermediate"},{"id":"c11","number":11,"title":"Neonatal Care & Resuscitation Basics","section":"Neonatal","difficulty":"Advanced"},{"id":"c12","number":12,"title":"Child Maltreatment Recognition","section":"Special Populations","difficulty":"Intermediate"},{"id":"c13","number":13,"title":"Children With Special Healthcare Needs & Technology Dependence","section":"Special Populations","difficulty":"Intermediate"},{"id":"c14","number":14,"title":"EMS Operations: Transport Decisions, Disaster & MCI Triage Involving Children","section":"Operations","difficulty":"Intermediate"}]},"chapters":{"c01":{"id":"c01","title":"Why Children Are Different: Developmental & Anatomic Considerations","shortTitle":"Why Children Are Different","estimatedStudyTime":26,"difficulty":"Beginner","learningObjectives":["Explain why 'children are not small adults' as an organizing principle of pediatric prehospital care.","Describe key airway anatomic differences between children and adults.","Describe key differences in pediatric breathing mechanics and metabolic demand.","Describe key differences in pediatric circulating blood volume and compensatory capacity.","Relate developmental stage to communication and cooperation during assessment.","Use age-banded normal vital signs as a baseline for recognizing abnormal findings."],"summary":[{"title":"Children Are Not Small Adults","content":"The single organizing idea behind PEPP is that children differ from adults anatomically, physiologically, developmentally, and psychosocially — not just in size. A treatment or assessment approach scaled down from an adult protocol without accounting for these differences will miss findings or cause harm. This chapter lays the anatomic and developmental groundwork that every later PEPP chapter builds on."},{"title":"Airway: Small, Anterior, and Easily Obstructed","content":"A child's tongue is proportionally larger relative to the oropharynx, the airway is narrower at every level, and the larynx sits more anterior and cephalad (higher in the neck) than in an adult. The narrowest part of the pediatric airway is subglottic (below the vocal cords) in young children, unlike the adult airway, which narrows at the cords. These differences make children more prone to airway obstruction from secretions, a large tongue, or swelling, and require different airway-positioning and equipment-sizing approaches than adult care."},{"title":"Breathing: Higher Demand, Less Reserve","content":"Children have a higher metabolic rate and oxygen consumption per kilogram than adults, but smaller functional residual capacity (oxygen reserve in the lungs). Infants are primarily diaphragmatic breathers with a more compliant (flexible) chest wall, meaning they generate less effective negative pressure and fatigue faster during increased work of breathing. The practical result: children desaturate faster than adults when breathing is compromised, and respiratory problems are the leading pathway to pediatric cardiac arrest."},{"title":"Circulation: Small Volume, Strong Compensation, Then Collapse","content":"A child's absolute circulating blood volume is small, so even modest-seeming blood or fluid losses represent a larger percentage of total volume than the same loss would in an adult. Children compensate remarkably well for volume loss through tachycardia and vasoconstriction, often maintaining a normal blood pressure until a large percentage of volume is lost — meaning blood pressure is a late and unreliable early warning sign in children. When compensation fails, children can decompensate rapidly and with little warning."},{"title":"Developmental Stage Shapes the Encounter","content":"How a child responds to assessment, and how a provider should approach them, changes by developmental stage: infants respond to caregivers' calm presence and are assessed largely by observation; toddlers and preschoolers fear separation from caregivers and unfamiliar equipment, and benefit from keeping the caregiver close and demonstrating equipment on a doll or the caregiver first; school-age children can usually cooperate with direct, honest explanation; adolescents want privacy, respect, and honesty, and may be interviewed partly apart from caregivers. Matching the approach to developmental stage improves both cooperation and the accuracy of the assessment."},{"title":"Why Age-Banded Vital Signs Matter","content":"Because normal heart rate, respiratory rate, and blood pressure change substantially across childhood, a single 'normal vitals' reference is useless in pediatrics. Every vital sign must be interpreted against the age-appropriate normal range (see the table in this chapter), and — critically — trends and the overall clinical picture (the Pediatric Assessment Triangle, covered next chapter) matter more than any single vital sign in isolation."}],"clinicalPearls":["'Children are not small adults' — anatomic, physiologic, developmental, and psychosocial differences change assessment and care at every step.","The pediatric airway's narrowest point is subglottic, below the vocal cords, unlike the adult airway.","Respiratory problems are the leading pathway to pediatric cardiac arrest — protecting breathing protects the whole child.","Blood pressure is a late sign in pediatric shock; children compensate well, then decompensate fast.","Match your approach to developmental stage — a toddler and an adolescent need very different communication styles."],"redFlags":["Using an unmodified adult mental model for airway, breathing, or circulation assessment in a child.","Reassurance from a 'normal' blood pressure in a child with tachycardia and other perfusion concerns.","Approaching a toddler by separating them from a caregiver or leading with unfamiliar equipment."],"commonMistakes":["Treating a single vital sign as normal or abnormal without checking it against the age-appropriate range.","Assuming a calm-appearing infant is not working hard to breathe, when diaphragmatic breathing and chest-wall compliance mask early distress.","Ignoring developmental stage and using the same communication approach for a toddler and a teenager."],"memoryAids":["Children are not small adults — different anatomy, physiology, development, and psychosocial needs.","Pediatric airway = narrow, anterior, subglottic narrowest point.","Compensate hard, then collapse fast — blood pressure lags in pediatric shock.","Match communication to developmental stage, not just to age in years."],"decisionTrees":[{"title":"Applying Age-Appropriate Context to Any Finding","content":"Vital sign or exam finding obtained\n  → Identify the child's age band (see Age-Banded Normal Vital Signs table)\n  → Compare the finding to that age band's normal range — NOT an adult or generic pediatric range\n  → Consider developmental stage for how the assessment itself was obtained (cooperative vs. observed-only)\n  → Weigh the finding within the overall clinical gestalt (Pediatric Assessment Triangle), not in isolation"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Developmental and Anatomic Considerations","courses/pals/data/pals/tables/c01.json — Age-Banded Normal Pediatric Vital Signs (reused exactly)"]},"c02":{"id":"c02","title":"The Pediatric Assessment Triangle","shortTitle":"Pediatric Assessment Triangle","estimatedStudyTime":35,"difficulty":"Beginner","learningObjectives":["Define the Pediatric Assessment Triangle (PAT) and its three legs.","Assess Appearance using observable behavioral characteristics.","Assess Work of Breathing using visual and auditory cues, without a stethoscope.","Assess Circulation to Skin using color and temperature cues.","Use the PAT to form a general impression of 'sick vs. not sick' and likely physiologic category.","Explain why the PAT is performed before, not instead of, hands-on primary assessment."],"summary":[{"title":"What the PAT Is","content":"The Pediatric Assessment Triangle (PAT) is PEPP's signature tool: a rapid, hands-off, across-the-room visual and auditory assessment performed within the first seconds of encountering a child, before you ever touch the patient. It has three legs — Appearance, Work of Breathing, and Circulation to Skin — assessed together to form a general impression of how sick the child is and which body system is likely involved, guiding the pace and priority of everything that follows."},{"title":"Leg 1 — Appearance","content":"Appearance captures the child's overall level of interaction with the environment and is often summarized with the mnemonic TICLS: Tone (moving spontaneously or limp), Interactiveness (alert and engaged, or uninterested), Consolability (can they be comforted, or are they inconsolable), Look/Gaze (do they fix their gaze on you or a caregiver, or stare blankly), and Speech/Cry (strong and appropriate for age, or weak/muffled/absent). Appearance is the single most sensitive PAT leg for detecting adequacy of oxygenation, ventilation, brain perfusion, and CNS function — an abnormal Appearance is a red flag even when the other two legs look normal."},{"title":"Leg 2 — Work of Breathing","content":"Work of Breathing is assessed by listening and looking, without a stethoscope: abnormal airway sounds (stridor, grunting, wheezing, muffled voice), abnormal positioning (tripod position, sniffing position, refusal to lie down), retractions (visible pulling in at the suprasternal, intercostal, or subcostal areas), and nasal flaring or head bobbing. Work of Breathing reflects the child's effort to compensate for an oxygenation or ventilation problem, and increases before oxygen saturation necessarily falls — it is an early window into respiratory status."},{"title":"Leg 3 — Circulation to Skin","content":"Circulation to Skin assesses perfusion by looking at skin and mucous membrane color: pallor (pale, poor perfusion), mottling (patchy discoloration), and cyanosis (bluish, indicating significant hypoxemia), assessed against the child's baseline skin tone in adequate lighting. This leg reflects how well the core is perfusing the periphery and is an early clue to shock, sometimes appearing before other perfusion signs are measurable."},{"title":"Putting the Three Legs Together","content":"No single leg is assessed in isolation — the pattern across all three legs points toward a likely physiologic category. Abnormal Appearance with normal Work of Breathing and Circulation suggests a primarily CNS/metabolic problem. Abnormal Appearance and Work of Breathing with normal Circulation suggests a respiratory problem. Abnormal Appearance and Circulation with normal Work of Breathing suggests a circulatory/shock problem. Abnormal findings across all three legs suggest a severe, multi-system problem (cardiopulmonary failure) requiring the most urgent response. This pattern recognition takes seconds and drives the pace of everything that follows."},{"title":"The PAT Comes First, Not Instead","content":"The PAT is completed before hands-on primary assessment (ABCDE) begins — it sets the general impression and urgency level that shapes how quickly and in what order the primary assessment proceeds, but it does not replace it. A child who looks fine on PAT still gets a full primary assessment; a child who looks critically ill on PAT gets that primary assessment started immediately and rapidly, potentially with simultaneous life-saving interventions. The PAT is the 'from the doorway' first 15 seconds of every pediatric encounter in PEPP."}],"clinicalPearls":["PAT = Appearance + Work of Breathing + Circulation to Skin — hands-off, done from across the room, in the first seconds of contact.","TICLS for Appearance: Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry.","Abnormal Appearance alone, even with normal breathing and circulation, is a red flag — it's the most sensitive PAT leg.","The PAT sets your pace; it never replaces the hands-on primary assessment that follows it."],"redFlags":["An inconsolable, limp, or gaze-unfocused child (abnormal Appearance) — treat as high acuity regardless of vital signs not yet obtained.","Retractions, grunting, or head bobbing (abnormal Work of Breathing) — signs of significant respiratory effort, act before full desaturation occurs.","Mottled or cyanotic skin (abnormal Circulation to Skin) — a perfusion problem is already underway."],"commonMistakes":["Reaching for a stethoscope or BP cuff before completing the hands-off PAT.","Treating one PAT leg as the whole picture instead of reading the pattern across all three.","Skipping the primary assessment because the PAT looked reassuring."],"memoryAids":["PAT legs: Appearance, Work of Breathing, Circulation to Skin.","TICLS: Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry.","1 abnormal leg = CNS/metabolic; 2 legs (Appearance+WOB) = respiratory; 2 legs (Appearance+Circ) = shock; all 3 = cardiopulmonary failure.","PAT is the first 15 seconds — from the doorway, before you touch the child."],"decisionTrees":[{"title":"Pediatric Assessment Triangle Pattern Recognition","content":"From across the room, assess all three legs simultaneously:\n  Appearance (TICLS) | Work of Breathing | Circulation to Skin\n\nPattern → Likely category:\n  Abnormal Appearance ONLY → CNS/metabolic problem\n  Abnormal Appearance + Work of Breathing → Respiratory problem\n  Abnormal Appearance + Circulation → Shock (circulatory problem)\n  Abnormal ALL THREE → Cardiopulmonary failure (highest urgency)\n  All THREE normal → Stable general impression, proceed to routine primary assessment\n\n  → In every case, PAT sets urgency, then proceed to full ABCDE primary assessment"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — The Pediatric Assessment Triangle","courses/pals/data/pals/tables/c01.json — Pediatric Assessment Triangle: Components and Findings (cross-referenced, not duplicated verbatim)"]},"c03":{"id":"c03","title":"Primary Assessment (ABCDE) & Scene Size-Up","shortTitle":"Primary Assessment (ABCDE)","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Perform a pediatric-appropriate scene size-up.","Perform the hands-on primary assessment in ABCDE order.","Identify and immediately treat life threats found during the primary assessment.","Explain the relationship between the PAT and the primary assessment.","Determine an overall patient priority (high vs. low acuity) from the primary assessment."],"summary":[{"title":"Scene Size-Up in the Pediatric Setting","content":"Scene size-up for a pediatric call includes standard precautions and hazard assessment, plus pediatric-specific attention: the mechanism of injury or nature of illness, the number of patients (children are frequently involved in multi-victim events like car crashes or household incidents), and early clues from the environment (medication bottles, home safety hazards, caregiver affect). Involving a calm caregiver early, when safe to do so, often improves both scene safety and the child's cooperation."},{"title":"The Primary Assessment: ABCDE","content":"After the PAT gives a general impression, the hands-on primary assessment follows the ABCDE sequence: Airway (patent? maintainable?), Breathing (rate, effort, breath sounds, oxygen saturation), Circulation (pulse rate/quality, skin perfusion, capillary refill, external bleeding), Disability (rapid neurologic check — AVPU or similar, pupils, blood glucose if altered), and Exposure (undress as needed to assess for injury/rash/other findings, then keep the child warm). This is the same spine used in PALS, but PEPP frames it as a field assessment and transport-decision tool rather than a resuscitation-team algorithm — see the PALS reviewer for cardiac-arrest-specific ABCDE depth."},{"title":"Treating Life Threats Immediately","content":"Any life threat identified during the primary assessment — an obstructed airway, absent or grossly inadequate breathing, uncontrolled hemorrhage — is treated the moment it is found, before moving to the next letter of ABCDE. The primary assessment is not a checklist to complete before acting; it is an ordered scan that triggers immediate intervention at whichever step reveals the problem."},{"title":"How the PAT and Primary Assessment Fit Together","content":"The PAT (previous chapter) is the hands-off, from-the-doorway general impression; the primary assessment is the hands-on, structured ABCDE exam that follows it. A high-acuity PAT (e.g., cardiopulmonary failure pattern) means the primary assessment proceeds immediately and rapidly, often with simultaneous interventions rather than a strict sequential exam. A reassuring PAT means the primary assessment proceeds at a calmer, still-thorough pace. Neither tool substitutes for the other."},{"title":"Assigning Priority","content":"The primary assessment concludes with an overall priority determination: high-priority (unstable PAT and/or ABCDE findings, needing rapid transport and possibly ALS intercept) versus low-priority (stable findings, allowing a more complete secondary assessment on scene). This priority decision — not a specific diagnosis — is the primary assessment's main deliverable, and it directly drives the pace of everything in the next chapter (history-taking and secondary assessment)."}],"clinicalPearls":["Scene size-up for pediatric calls includes hazard assessment plus early attention to mechanism/nature of illness and caregiver affect.","ABCDE: Airway, Breathing, Circulation, Disability, Exposure — treat each life threat the moment it's found, don't wait to finish the checklist.","The PAT sets the pace; the primary assessment is the hands-on exam that follows it — neither replaces the other.","The primary assessment's main output is a priority decision (high vs. low), not a diagnosis."],"redFlags":["An obstructed or threatened airway found during 'A' — stop and treat before continuing to 'B'.","Absent breath sounds or grossly inadequate breathing found during 'B' — treat immediately.","Uncontrolled external hemorrhage found during 'C' — control it before moving on."],"commonMistakes":["Completing the entire ABCDE sequence before treating a life threat found early in the exam.","Skipping the primary assessment because the PAT looked reassuring.","Failing to reassess priority as new findings emerge."],"memoryAids":["ABCDE: Airway, Breathing, Circulation, Disability, Exposure.","Find it, fix it — treat the life threat the moment you find it, not after finishing the alphabet.","PAT sets the pace, ABCDE does the exam.","Primary assessment's job: decide priority, not diagnosis."],"decisionTrees":[{"title":"Pediatric Primary Assessment Sequence","content":"Scene size-up (safety, precautions, MOI/NOI, patient count)\n  → PAT (from previous chapter) sets urgency\n  → Primary assessment, ABCDE, in order:\n     A — Airway: patent? maintainable? → fix immediately if not\n     B — Breathing: rate, effort, sounds, SpO2 → fix immediately if inadequate\n     C — Circulation: pulse, perfusion, cap refill, bleeding → fix immediately if compromised\n     D — Disability: rapid neuro check, glucose if altered\n     E — Exposure: assess for injury/rash, then keep warm\n  → Assign priority: HIGH (rapid transport/ALS intercept) or LOW (proceed to secondary assessment on scene)"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Primary Assessment","courses/pals/ — ABCDE spine cross-referenced, not duplicated for cardiac-arrest-specific depth"]},"c04":{"id":"c04","title":"History Taking, Secondary Assessment & Family-Centered Communication","shortTitle":"History & Secondary Assessment","estimatedStudyTime":28,"difficulty":"Intermediate","learningObjectives":["Obtain a pediatric-focused history using SAMPLE and event-specific questions.","Perform a developmentally appropriate secondary assessment/focused exam.","Apply family-centered care principles during assessment and treatment.","Recognize special communication needs (hearing-impaired, non-English-speaking, developmentally delayed).","Explain how caregiver presence and involvement can improve both assessment and the child's experience."],"summary":[{"title":"SAMPLE History in Children","content":"The SAMPLE history — Signs/Symptoms, Allergies, Medications, Past medical history, Last oral intake, Events leading up to the incident — applies to pediatric patients with added emphasis on birth history and developmental milestones for infants, immunization status, and growth/weight trends for medication dosing. Caregivers are usually the primary historians for young children, but school-age children and adolescents should be asked directly whenever possible, with the caregiver's account used to confirm or supplement rather than replace the child's own report."},{"title":"The Secondary Assessment: Focused or Detailed Exam","content":"The secondary assessment follows the primary assessment and history, and is either a focused exam (targeted to the chief complaint, for stable/low-priority patients) or a rapid, more limited exam (for high-priority patients, performed en route). The physical exam order itself is often developmentally adjusted: for infants and toddlers, a toe-to-head sequence (least threatening areas first) improves cooperation, while school-age children and adolescents can typically tolerate a standard head-to-toe sequence."},{"title":"Family-Centered Care","content":"Family-centered care treats the caregiver as a partner in the child's care rather than an obstacle to manage. In most situations, allowing a caregiver to remain present (including during many procedures and even resuscitation, with a dedicated support person when feasible) reduces the child's distress and improves cooperation, without meaningfully slowing care. Explaining what you are doing and why, in age-appropriate and caregiver-appropriate language, builds trust and improves the accuracy of the history you receive."},{"title":"Special Communication Needs","content":"Some encounters require adapted communication: for a hearing-impaired child or caregiver, face the person directly, speak clearly (not necessarily loudly), and use written notes or an interpreter service as needed; for a non-English-speaking family, use professional interpretation services rather than relying on a child to interpret for their own care; for a child with developmental delay or autism spectrum differences, take cues from the caregiver about the child's usual communication style, minimize sensory overload where possible, and allow extra time. Adapting communication is a clinical skill, not an optional courtesy — it materially affects the quality of the history and exam you obtain."},{"title":"Building the Full Picture","content":"History-taking and secondary assessment together answer the question the primary assessment could not: not just 'how sick is this child right now,' but 'why, and what has been happening.' Combined with the PAT and primary assessment, this completes PEPP's four-part assessment sequence — PAT, primary assessment, history, secondary assessment — which then informs the treatment and transport decisions covered later in this course."}],"clinicalPearls":["SAMPLE in pediatrics adds emphasis on birth history/milestones (infants), immunizations, and growth/weight for dosing.","Ask school-age children and adolescents directly; use caregiver accounts to supplement, not replace, the child's own report.","Toe-to-head exam order reduces distress in infants/toddlers; head-to-toe works for school-age children and adolescents.","Family-centered care — keeping a caregiver present, including during many procedures — reduces distress without slowing care."],"redFlags":["Relying on a child to interpret medical information for their own non-English-speaking caregiver.","Excluding a calm, cooperative caregiver from the room by default rather than by clinical necessity.","Ignoring a caregiver's guidance on a developmentally different child's usual communication style."],"commonMistakes":["Using a head-to-toe exam order on a frightened toddler when toe-to-head would improve cooperation.","Treating the caregiver's account as automatically more reliable than an age-appropriate child's own report.","Skipping professional interpretation services when a family member could 'informally translate.'"],"memoryAids":["SAMPLE: Signs/Symptoms, Allergies, Medications, Past history, Last intake, Events.","Toe-to-head for the young and scared; head-to-toe for the older and cooperative.","Family-centered care: partner with the caregiver, don't just tolerate them.","Interpretation services, not a frightened child, translate for a non-English-speaking parent."],"decisionTrees":[{"title":"History & Secondary Assessment Sequence","content":"After primary assessment and priority assignment:\n  → Obtain SAMPLE history (ask child directly if age-appropriate; caregiver supplements)\n  → Choose exam order by development: infant/toddler → toe-to-head; school-age/adolescent → head-to-toe\n  → Perform focused (stable) or rapid (high-priority) secondary exam accordingly\n  → Apply family-centered care: keep caregiver present/involved when feasible\n  → Adapt communication for special needs: interpretation services, hearing-impaired accommodations, developmental differences\n  → Integrate findings with PAT + primary assessment to finalize treatment/transport plan"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — History Taking and Secondary Assessment","AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Family-Centered Care and Communication"]},"c05":{"id":"c05","title":"Respiratory Distress & Respiratory Failure","shortTitle":"Respiratory Distress & Failure","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Distinguish respiratory distress from respiratory failure.","Recognize the four categories of pediatric respiratory compromise.","Identify early PAT/exam findings that predict impending respiratory failure.","Describe field management appropriate for respiratory distress and failure.","Explain why respiratory problems are the leading pathway to pediatric cardiac arrest."],"summary":[{"title":"Distress vs Failure","content":"Respiratory distress describes a child who is working hard to breathe but is still compensating — increased work of breathing (retractions, nasal flaring, grunting), often with tachypnea, but generally adequate oxygenation and mental status. Respiratory failure describes a child whose compensation has failed — inadequate oxygenation and/or ventilation is now present, marked by altered mental status, cyanosis, bradypnea or irregular breathing, and profound fatigue. The transition from distress to failure can happen quickly, and PEPP teaches recognizing the early warning signs of that transition as a top priority."},{"title":"The Four Categories of Pediatric Respiratory Compromise","content":"Pediatric respiratory problems are organized into four categories by the level of the problem. Upper airway obstruction (e.g., croup, foreign body, epiglottitis) typically causes stridor. Lower airway disease (e.g., asthma, bronchiolitis) typically causes wheezing and prolonged expiration. Lung tissue (parenchymal) disease (e.g., pneumonia, pulmonary edema) typically causes grunting, crackles, and diminished breath sounds. Disordered control of breathing (e.g., from a CNS problem, toxin, or neuromuscular disease) causes an irregular rate/pattern without the classic sounds of the other three categories. Categorizing by mechanism guides both what to expect on exam and which field treatment is appropriate."},{"title":"Early Warning Signs of Impending Failure","content":"Signals that a child is approaching respiratory failure, even before oxygen saturation drops: worsening or new grunting, decreasing (not increasing) work of breathing in a child who was previously struggling hard — reflecting exhaustion rather than improvement — a change in Appearance on the PAT (from anxious/agitated to lethargic), and a falling or irregular respiratory rate after a period of tachypnea. Any of these should prompt immediate escalation of support, since they often precede a measurable drop in SpO2."},{"title":"Field Management","content":"For respiratory distress, field management is generally positioning of comfort, supplemental oxygen, and treatment targeted to the likely category (e.g., nebulized bronchodilator for suspected lower-airway disease), with close monitoring for any sign of transition toward failure. For respiratory failure, field management is assisted ventilation — bag-mask ventilation with high-flow oxygen — and rapid transport; PEPP frames this as the field recognition and initial stabilization step, with drug-assisted airway management and cardiac-arrest-specific ventilation parameters covered in depth by the PALS reviewer."},{"title":"Why This Matters So Much in Pediatrics","content":"Respiratory problems are the leading pathway to pediatric cardiac arrest — unlike adults, where a primary cardiac event is more common. This means that recognizing and treating respiratory distress before it becomes failure is one of the single highest-yield interventions in all of pediatric prehospital care, and is a recurring theme across nearly every later chapter in this course."}],"clinicalPearls":["Respiratory distress = compensating; respiratory failure = compensation has failed. The transition can happen fast.","Four categories: upper airway (stridor), lower airway (wheeze), lung tissue (grunting/crackles), disordered control of breathing (irregular pattern, no classic sounds).","Decreasing work of breathing in a previously struggling child can mean exhaustion, not improvement — a dangerous, easily misread sign.","Respiratory problems are the leading pathway to pediatric cardiac arrest — early recognition and treatment prevent the arrest, not just treat it."],"redFlags":["A child who was struggling hard to breathe now appears calmer and less effortful — verify this isn't exhaustion before feeling reassured.","New or worsening grunting.","Appearance shifting from anxious/agitated to lethargic on repeat PAT."],"commonMistakes":["Mistaking a fatiguing child's 'calmer' appearance for genuine improvement.","Treating all four respiratory categories the same way instead of matching treatment to the likely mechanism.","Waiting for SpO2 to fall before escalating support, when other findings already signal deterioration."],"memoryAids":["Distress compensates, failure collapses.","Stridor = upper, wheeze = lower, grunt/crackles = tissue, irregular-no-sound = control problem.","'Calmer' after struggling hard is a red flag, not relief — check for exhaustion.","Respiratory first, cardiac second — that's the pediatric arrest pathway."],"decisionTrees":[{"title":"Respiratory Distress vs Failure Recognition and Management","content":"Respiratory complaint\n  → Categorize: Upper airway (stridor) | Lower airway (wheeze) | Lung tissue (grunt/crackles) | Disordered control (irregular, no classic sound)\n  → Assess for distress vs failure signs:\n     Distress: increased WOB, tachypnea, adequate oxygenation/mentation → position of comfort, O2, category-targeted treatment, close monitoring\n     Failure (or transitioning): altered mentation, cyanosis, bradypnea/irregular pattern, exhaustion (including 'improving' WOB after struggling) → assist ventilation (BVM + high-flow O2), rapid transport\n  → For arrest-level airway/ventilation depth beyond field stabilization: see PALS reviewer"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Respiratory Emergencies","courses/pals/data/pals/tables/c04.json — Four Categories of Pediatric Respiratory Compromise (cross-referenced terminology)"]},"c06":{"id":"c06","title":"Shock Recognition & Field Management","shortTitle":"Shock Recognition & Management","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Define shock as inadequate tissue perfusion rather than a specific blood pressure value.","Distinguish compensated from decompensated (hypotensive) shock in children.","Recognize the major categories of pediatric shock and their field-relevant distinguishing features.","Identify the PAT and vital sign findings that suggest shock.","Describe field management priorities for compensated and decompensated shock."],"summary":[{"title":"Shock Is a Perfusion Problem, Not a Blood Pressure Number","content":"Shock is inadequate delivery of oxygen and nutrients to meet tissue demands — it is a clinical diagnosis based on perfusion, not a specific blood pressure. Children compensate for shock remarkably well through tachycardia and vasoconstriction, which means blood pressure can remain normal well into shock. By the time hypotension appears, a child has exhausted their compensatory mechanisms and is decompensating rapidly. This is why PEPP emphasizes recognizing compensated shock from perfusion signs — capillary refill, skin color/temperature, pulse quality, mental status — rather than waiting for a low blood pressure reading."},{"title":"Compensated vs Decompensated Shock","content":"Compensated shock: tachycardia, delayed capillary refill, cool/mottled skin (or warm/flushed in early distributive/septic shock), narrowed pulse pressure, and a normal systolic blood pressure for age. Decompensated shock: the same perfusion findings plus hypotension for age, and typically altered mental status. The transition from compensated to decompensated shock can be abrupt, and hypotension in a child is a late and ominous sign, not an early warning."},{"title":"Major Categories of Pediatric Shock","content":"Hypovolemic shock (most common in children overall) results from fluid or blood loss — vomiting/diarrhea with dehydration, hemorrhage, or burns. Distributive shock results from abnormal vessel tone/permeability — septic shock, anaphylactic shock, and neurogenic shock (rare in children). Cardiogenic shock results from pump failure — congenital heart disease, myocarditis, or arrhythmia. Obstructive shock results from a physical obstruction to blood flow — tension pneumothorax, cardiac tamponade, or massive pulmonary embolism (rare in children). Recognizing the likely category from history and exam guides field treatment (e.g., fluid resuscitation for hypovolemic shock versus needle decompression for obstructive shock from tension pneumothorax)."},{"title":"Field Recognition","content":"On the PAT, shock often first appears as an Appearance abnormality (irritability progressing to lethargy) with normal-appearing work of breathing, or as abnormal Circulation to Skin (pallor, mottling, cyanosis). On the primary assessment, look for tachycardia out of proportion to fever/anxiety, delayed capillary refill (over 2 seconds), weak or absent peripheral pulses with strong central pulses, cool extremities with a temperature gradient, and narrowed pulse pressure. Fever plus poor perfusion with warm, flushed skin and bounding pulses suggests early septic (distributive) shock rather than hypovolemic shock."},{"title":"Field Management","content":"General priorities: supplemental oxygen, positioning (supine, legs elevated if tolerated), keep the child warm, and rapid transport. For suspected hypovolemic or septic shock, isotonic fluid boluses are indicated per local protocol. For suspected anaphylactic shock, epinephrine is the priority treatment. For suspected obstructive shock from tension pneumothorax, needle decompression is indicated per protocol/scope of practice. PEPP frames this chapter as field recognition and initial stabilization; drug dosing tables and advanced resuscitation algorithms for shock and arrest are the domain of the PALS reviewer."}],"clinicalPearls":["Shock is a perfusion problem — blood pressure can be normal in compensated shock. Don't wait for hypotension to recognize shock.","Hypotension in a child is a late, ominous sign — it means decompensation, not the first sign of shock.","Warm, flushed skin with bounding pulses and fever can be shock too — early distributive (septic) shock often looks different from cold, mottled hypovolemic shock.","Match treatment to category: fluids for hypovolemic/septic, epinephrine for anaphylactic, needle decompression for obstructive tension pneumothorax."],"redFlags":["Delayed capillary refill (>2 seconds) with normal blood pressure — compensated shock until proven otherwise.","Tachycardia out of proportion to fever or anxiety.","Any hypotension for age — this represents decompensated shock and is a late finding."],"commonMistakes":["Waiting for hypotension before recognizing and treating shock.","Assuming all shock presents as cold and mottled, missing warm, flushed early septic shock.","Treating every shock category with fluids alone, without considering epinephrine (anaphylactic) or needle decompression (obstructive) when indicated."],"memoryAids":["Normal BP does not mean no shock — compensated shock hides behind a normal number.","Cold and mottled or warm and flushed — both can be shock.","Four categories: low volume (hypovolemic), bad tone (distributive), bad pump (cardiogenic), blocked flow (obstructive).","Hypotension = decompensating now, not a warning of shock to come — it already arrived."],"decisionTrees":[{"title":"Pediatric Shock Recognition and Category-Matched Management","content":"Suspect shock from PAT/primary assessment (abnormal Appearance and/or Circulation to Skin, tachycardia, delayed cap refill, weak pulses)\n  → Check blood pressure for age:\n     Normal BP + perfusion signs → Compensated shock\n     Low BP for age + perfusion signs (+ often altered mentation) → Decompensated shock (late, ominous)\n  → Identify likely category from history/exam:\n     Fluid/blood loss history → Hypovolemic → isotonic fluid bolus per protocol\n     Fever + warm/flushed or cold/mottled + poor perfusion → Distributive/septic → isotonic fluid bolus per protocol\n     Allergen exposure + rash/angioedema/wheeze → Anaphylactic (distributive) → epinephrine priority\n     Cardiac history/muffled heart sounds/JVD → Cardiogenic → cautious fluids, avoid overload\n     Trauma + unilateral absent breath sounds/tracheal deviation → Obstructive (tension pneumothorax) → needle decompression per protocol\n  → Supportive care: oxygen, positioning, keep warm, rapid transport\n  → For advanced shock/arrest resuscitation depth: see PALS reviewer"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Shock","courses/pals/data/pals — cross-referenced for advanced shock/arrest management depth"]},"c07":{"id":"c07","title":"Cardiac Emergencies & Rhythm Recognition","shortTitle":"Cardiac Emergencies","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Explain why primary cardiac events are rare in children compared to adults.","Recognize field presentations of pediatric bradycardia, tachycardia, and cardiac arrest.","Identify congenital heart disease as a risk factor for pediatric cardiac emergencies.","Describe the field priority of treating the underlying cause of bradycardia (usually hypoxia) rather than the rhythm alone.","Understand when to defer to the PALS reviewer for arrest algorithms and drug dosing."],"summary":[{"title":"Primary Cardiac Events Are Rare in Children","content":"Unlike adults, where primary cardiac events (e.g., myocardial infarction, primary ventricular fibrillation) are a common cause of sudden collapse, primary cardiac disease is a rare cause of pediatric emergencies. Most pediatric cardiac problems are secondary — bradycardia from hypoxia, or arrhythmia in a child with known congenital heart disease. This chapter focuses on field recognition of these secondary presentations; it does not replace the PALS reviewer's depth on arrest rhythms, defibrillation, and drug dosing."},{"title":"Bradycardia: Treat the Cause, Not Just the Rhythm","content":"The most common serious pediatric dysrhythmia encountered in the field is bradycardia, and it is almost always caused by hypoxia (or less commonly, increased vagal tone, hypothermia, or increased intracranial pressure). The field priority for symptomatic bradycardia is to address the underlying cause — oxygenate and ventilate first — rather than treating the rhythm number in isolation. A bradycardic, poorly perfusing infant is usually a respiratory or hypoxia problem until proven otherwise."},{"title":"Tachycardia: Sinus vs Supraventricular","content":"Sinus tachycardia is a compensatory response (fever, pain, anxiety, dehydration, shock) and resolves as the underlying cause is treated; rates are usually variable and rarely exceed about 220 bpm in infants. Supraventricular tachycardia (SVT) is a primary rhythm disturbance with a fixed, very rapid rate (often >220 bpm in infants, >180 bpm in older children) that does not vary with stimulation, and can itself cause poor perfusion if sustained. Distinguishing the two by history (fever/pain/dehydration vs sudden onset with no clear trigger) and rate pattern guides field urgency."},{"title":"Congenital Heart Disease as a Risk Factor","content":"Children with known congenital heart disease (repaired or unrepaired) are at elevated risk for arrhythmia, heart failure, and cardiogenic shock, and may have baseline vital signs or oxygen saturations that differ from typical pediatric norms — always ask caregivers about the child's 'normal' baseline. Family history clues (sudden unexplained death in young relatives) can also suggest an underlying cardiac channelopathy risk in an otherwise unexplained pediatric collapse."},{"title":"Field Recognition and Initial Stabilization","content":"Field priorities are recognition (PAT + primary assessment + monitor/rhythm strip if available), identifying reversible causes (especially hypoxia), and rapid transport with continuous reassessment. This chapter deliberately does not reproduce arrest algorithms, defibrillation/cardioversion energy doses, or antiarrhythmic drug dosing — these are covered in full depth in the PALS reviewer, which should be used for any patient in or approaching cardiac arrest."}],"clinicalPearls":["Primary cardiac events are rare in children — most pediatric bradycardia is caused by hypoxia, not primary heart disease.","Treat the cause of bradycardia (usually oxygenation/ventilation) before treating the number.","Sinus tachycardia varies with the underlying cause and stimulation; SVT is fixed, very rapid, and doesn't vary.","Ask about a child's known congenital heart disease and their personal 'normal' baseline vitals/SpO2 — it changes what's abnormal for them."],"redFlags":["Bradycardia with poor perfusion in an infant — treat as a hypoxia/respiratory emergency until proven otherwise.","A fixed, very rapid heart rate that does not vary with stimulation — suspect SVT.","Family history of sudden unexplained death in a young relative, in a child with unexplained collapse or syncope."],"commonMistakes":["Treating bradycardia as a primary cardiac rhythm problem without first addressing oxygenation/ventilation.","Failing to distinguish sinus tachycardia (variable, has a clear trigger) from SVT (fixed, very rapid).","Not asking about a child's baseline vitals/SpO2 when they have known congenital heart disease."],"memoryAids":["Bradycardia in a child = hypoxia until proven otherwise — fix the airway/breathing first.","Sinus tachy varies with the cause; SVT doesn't vary and is very fast.","Know their normal — congenital heart disease patients may have a different baseline.","For arrest rhythms and drug doses, go to PALS — this chapter is recognition, not resuscitation depth."],"decisionTrees":[{"title":"Pediatric Cardiac Emergency Field Recognition","content":"Abnormal heart rate or rhythm noted\n  → Bradycardia + poor perfusion → Suspect hypoxia (or vagal tone/hypothermia/increased ICP) → prioritize oxygenation/ventilation, treat underlying cause\n  → Tachycardia:\n     Variable rate, clear trigger (fever/pain/dehydration/shock) → Sinus tachycardia → treat underlying cause\n     Fixed, very rapid rate, no clear trigger, does not vary with stimulation → Suspect SVT → rapid transport, notify receiving facility\n  → Known congenital heart disease or family history of sudden unexplained death → heightened suspicion for cardiac cause, ask caregiver for patient's normal baseline\n  → Any patient in or approaching cardiac arrest → transition immediately to PALS arrest algorithms (not covered in this chapter)"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Cardiac Emergencies","courses/pals/data/pals — authoritative source for arrest algorithms, defibrillation/cardioversion dosing, and antiarrhythmic drug dosing (not duplicated here)"]},"c08":{"id":"c08","title":"Neurologic Emergencies: Altered Mental Status & Seizures","shortTitle":"Neurologic Emergencies","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Apply the AVPU scale and PAT Appearance findings to recognize altered mental status in children.","List the common reversible causes of pediatric altered mental status using the AEIOU-TIPS framework.","Describe field management of active pediatric seizures, including status epilepticus.","Recognize febrile seizures as generally benign and distinguish them from more concerning seizure presentations.","Identify field priorities for a child with suspected increased intracranial pressure."],"summary":[{"title":"Recognizing Altered Mental Status","content":"The PAT's Appearance leg is often the first clue to altered mental status, before a formal AVPU (Alert, Voice, Pain, Unresponsive) assessment is completed. Any child who is not appropriately alert and interactive for their developmental stage — or who has an abnormal TICLS finding such as poor eye contact or an abnormal cry — should prompt a full neurologic assessment. Serial reassessment matters: a trend toward decreasing responsiveness is more concerning than a single snapshot value."},{"title":"Reversible Causes: AEIOU-TIPS","content":"A useful framework for reversible causes of pediatric altered mental status is AEIOU-TIPS: Alcohol/substance use, Epilepsy/seizure (postictal state), Infection, Overdose/opioids, Uremia/metabolic, Trauma/temperature, Insulin/hypoglycemia, Psychiatric, Shock/stroke. Hypoglycemia deserves particular emphasis in children because it is common, rapidly reversible, and easily checked in the field with a glucose meter — every altered child should have a glucose check when available."},{"title":"Seizures: Field Management","content":"Most pediatric seizures are brief and self-limited. Field priorities during an active seizure are protecting the airway (positioning, suction as needed — do not put anything in the mouth), protecting the child from injury, checking glucose, and timing the seizure. A seizure lasting more than 5 minutes, or repeated seizures without return to baseline between them, meets the definition of status epilepticus and is a time-critical emergency requiring rapid escalation of care and transport; benzodiazepine dosing for status epilepticus is detailed in the PALS reviewer."},{"title":"Febrile Seizures","content":"Febrile seizures are the most common pediatric seizure type, typically occurring in children 6 months to 5 years with a rapidly rising fever. A simple febrile seizure is generalized, lasts less than 15 minutes, and does not recur within 24 hours — these are generally benign, and the child typically returns to baseline mental status afterward. A complex febrile seizure (focal features, lasting more than 15 minutes, or recurring within 24 hours) or any seizure in a child who does not return to baseline warrants a higher level of concern and should not be assumed to be a simple febrile seizure."},{"title":"Suspected Increased Intracranial Pressure","content":"Signs suggesting increased intracranial pressure include a bulging fontanelle (infants), a decreasing level of consciousness, an irregular respiratory pattern, and — as a late and ominous finding — the Cushing triad (hypertension, bradycardia, irregular respirations). Field priorities are avoiding hypoxia and hypotension (both worsen secondary brain injury), positioning to avoid jugular venous compression, and rapid transport; specific hyperventilation/hyperosmolar therapy parameters are beyond this chapter's field-recognition scope."}],"clinicalPearls":["Every altered child gets a glucose check when available — hypoglycemia is common and rapidly reversible.","AEIOU-TIPS is a useful recall framework for reversible causes of altered mental status.","A seizure lasting more than 5 minutes, or repeated seizures without return to baseline, is status epilepticus — a time-critical emergency.","Simple febrile seizures are generalized, under 15 minutes, don't recur in 24 hours, and the child returns to baseline — anything more should raise concern."],"redFlags":["Any altered child without a glucose check performed when a meter is available.","Seizure activity lasting more than 5 minutes or recurring without return to baseline (status epilepticus).","Bulging fontanelle, irregular respirations, or the Cushing triad (hypertension, bradycardia, irregular respirations) suggesting increased intracranial pressure."],"commonMistakes":["Assuming all pediatric seizures with fever are simple febrile seizures without checking duration/recurrence/focality.","Delaying a glucose check in an altered child when a meter is available.","Placing an object in the mouth of a seizing child (unnecessary and can cause injury)."],"memoryAids":["AEIOU-TIPS: reversible causes of altered mental status.","5 minutes = status epilepticus — the clock matters.","Simple febrile seizure: generalized, under 15 minutes, no recurrence in 24 hours, back to baseline after.","Cushing triad = late and bad: high BP, low HR, irregular breathing."],"decisionTrees":[{"title":"Pediatric Altered Mental Status and Seizure Field Approach","content":"Altered mental status noted (PAT Appearance abnormal / AVPU below Alert)\n  → Check glucose when available → treat hypoglycemia per protocol if present\n  → Consider AEIOU-TIPS causes: Alcohol/substance, Epilepsy/postictal, Infection, Overdose, Uremia/metabolic, Trauma/temperature, Insulin/hypoglycemia, Psychiatric, Shock/stroke\n  → If actively seizing:\n     Protect airway/position, protect from injury, time the seizure, check glucose\n     <5 minutes and resolves, returns to baseline, fits simple febrile seizure pattern → supportive care, transport for evaluation\n     ≥5 minutes OR repeated seizures without return to baseline → Status epilepticus → time-critical emergency, escalate immediately (see PALS reviewer for benzodiazepine dosing)\n  → If signs of increased intracranial pressure (bulging fontanelle, irregular respirations, Cushing triad) → avoid hypoxia/hypotension, position to avoid jugular compression, rapid transport"}],"references":["AAP Pediatric Education for Prehospital Professionals (PEPP), 4th Edition — Neurologic Emergencies","courses/pals/data/pals — cross-referenced for status epilepticus drug dosing and advanced resuscitation depth"]}},"flashcards":{"c01":{"chapter":"c01","cards":[{"id":"c01_fc01","question":"What is the single organizing principle behind PEPP's approach to pediatric care?","answer":"Children are not small adults — they differ anatomically, physiologically, developmentally, and psychosocially, not just in size.","category":"Core Concepts"},{"id":"c01_fc02","question":"Where is the narrowest point of a young child's airway?","answer":"Subglottic (below the vocal cords) — unlike the adult airway, which narrows at the vocal cords.","category":"Airway"},{"id":"c01_fc03","question":"Why is a child's tongue an airway concern?","answer":"It is proportionally larger relative to the oropharynx than an adult's, making obstruction more likely.","category":"Airway"},{"id":"c01_fc04","question":"How does a child's metabolic rate/oxygen consumption compare to an adult's?","answer":"Higher per kilogram, combined with smaller functional residual capacity (oxygen reserve) — children desaturate faster.","category":"Breathing"},{"id":"c01_fc05","question":"What type of breathers are infants primarily?","answer":"Diaphragmatic breathers, with a more compliant (flexible) chest wall than older children/adults.","category":"Breathing"},{"id":"c01_fc06","question":"What is the leading pathway to pediatric cardiac arrest?","answer":"Respiratory problems — unlike adults, where cardiac causes predominate.","category":"Breathing"},{"id":"c01_fc07","question":"Why is blood pressure a late sign of shock in children?","answer":"Children compensate well for volume loss via tachycardia and vasoconstriction, maintaining normal BP until a large percentage of volume is lost.","category":"Circulation"},{"id":"c01_fc08","question":"What happens once a child's compensatory mechanisms for shock fail?","answer":"Rapid decompensation with little warning.","category":"Circulation"},{"id":"c01_fc09","question":"How should you approach a toddler or preschooler during assessment?","answer":"Keep the caregiver close, demonstrate equipment on a doll or the caregiver first, minimize separation anxiety triggers.","category":"Assessment"},{"id":"c01_fc10","question":"How should you approach an adolescent during assessment?","answer":"With privacy, respect, and honesty; consider interviewing partly apart from caregivers.","category":"Assessment"},{"id":"c01_fc11","question":"Why is a single 'normal vitals' reference useless in pediatrics?","answer":"Normal heart rate, respiratory rate, and blood pressure change substantially across childhood age bands.","category":"Assessment"},{"id":"c01_fc12","question":"What matters more than any single vital sign in isolation?","answer":"Trends over time and the overall clinical picture (the Pediatric Assessment Triangle).","category":"Assessment"},{"id":"c01_fc13","question":"Why can a child's absolute blood volume loss seem 'modest' but still be dangerous?","answer":"A child's total circulating blood volume is small, so the same absolute loss represents a larger percentage of total volume than in an adult.","category":"Circulation"},{"id":"c01_fc14","question":"How does the pediatric larynx position differ from an adult's?","answer":"It sits more anterior and cephalad (higher in the neck).","category":"Airway"}]},"c02":{"chapter":"c02","cards":[{"id":"c02_fc01","question":"What are the three legs of the Pediatric Assessment Triangle (PAT)?","answer":"Appearance, Work of Breathing, and Circulation to Skin.","category":"PAT"},{"id":"c02_fc02","question":"What does TICLS stand for?","answer":"Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry — the components of Appearance.","category":"PAT"},{"id":"c02_fc03","question":"Why is Appearance the most sensitive PAT leg?","answer":"It reflects adequacy of oxygenation, ventilation, brain perfusion, and CNS function — abnormal Appearance is a red flag even with normal breathing/circulation.","category":"PAT"},{"id":"c02_fc04","question":"How is Work of Breathing assessed?","answer":"By looking and listening without a stethoscope: abnormal sounds, abnormal positioning, retractions, nasal flaring, head bobbing.","category":"PAT"},{"id":"c02_fc05","question":"How is Circulation to Skin assessed?","answer":"By skin/mucous membrane color: pallor, mottling, or cyanosis, compared to the child's baseline in adequate lighting.","category":"PAT"},{"id":"c02_fc06","question":"What does abnormal Appearance alone (normal WOB and Circulation) suggest?","answer":"A primarily CNS/metabolic problem.","category":"PAT"},{"id":"c02_fc07","question":"What does abnormal Appearance + Work of Breathing suggest?","answer":"A respiratory problem.","category":"PAT"},{"id":"c02_fc08","question":"What does abnormal Appearance + Circulation suggest?","answer":"A shock/circulatory problem.","category":"PAT"},{"id":"c02_fc09","question":"What does abnormality across all three PAT legs suggest?","answer":"Cardiopulmonary failure — the most urgent category.","category":"PAT"},{"id":"c02_fc10","question":"When is the PAT performed relative to the primary assessment?","answer":"Before it — the PAT is hands-off and sets the pace/urgency, but does not replace the hands-on primary (ABCDE) assessment that follows.","category":"PAT"},{"id":"c02_fc11","question":"Is the PAT performed with a stethoscope or BP cuff?","answer":"No — it is entirely hands-off, done visually and by listening from across the room.","category":"PAT"},{"id":"c02_fc12","question":"What does 'retractions' mean in the Work of Breathing assessment?","answer":"Visible pulling in of the chest wall at the suprasternal, intercostal, or subcostal areas during breathing effort.","category":"PAT"},{"id":"c02_fc13","question":"Why does Work of Breathing increase before oxygen saturation falls?","answer":"Increased effort reflects the body's compensation for an oxygenation/ventilation problem, occurring before desaturation is measurable.","category":"PAT"},{"id":"c02_fc14","question":"A child looks completely normal on PAT. What should you still do?","answer":"Proceed to a full hands-on primary assessment — a normal PAT does not skip that step, it just sets a calmer pace.","category":"PAT"}]},"c03":{"chapter":"c03","cards":[{"id":"c03_fc01","question":"What does ABCDE stand for in the pediatric primary assessment?","answer":"Airway, Breathing, Circulation, Disability, Exposure.","category":"Primary Assessment"},{"id":"c03_fc02","question":"When is a life threat found during ABCDE treated?","answer":"Immediately, the moment it is found — not after completing the rest of the checklist.","category":"Primary Assessment"},{"id":"c03_fc03","question":"What is assessed under 'Disability' in pediatric ABCDE?","answer":"A rapid neurologic check (e.g., AVPU), pupils, and blood glucose if mental status is altered.","category":"Primary Assessment"},{"id":"c03_fc04","question":"What is assessed under 'Exposure'?","answer":"Undressing as needed to check for injury or rash, then keeping the child warm.","category":"Primary Assessment"},{"id":"c03_fc05","question":"How does the PAT relate to the primary assessment?","answer":"The PAT (hands-off) comes first and sets urgency/pace; the primary assessment (hands-on ABCDE) follows and does not get skipped even with a reassuring PAT.","category":"Assessment"},{"id":"c03_fc06","question":"What is the main deliverable of the primary assessment?","answer":"An overall priority decision — high vs. low acuity — not a specific diagnosis.","category":"Primary Assessment"},{"id":"c03_fc07","question":"What pediatric-specific factors are added to scene size-up?","answer":"Mechanism of injury/nature of illness, number of patients (multi-victim events are common), and environmental clues (medications, hazards, caregiver affect).","category":"Scene Size-Up"},{"id":"c03_fc08","question":"What determines whether the primary assessment proceeds rapidly with simultaneous interventions vs. at a calmer pace?","answer":"The urgency level established by the preceding PAT.","category":"Assessment"},{"id":"c03_fc09","question":"What are components of the 'Circulation' step in ABCDE?","answer":"Pulse rate/quality, skin perfusion, capillary refill, and external bleeding.","category":"Primary Assessment"},{"id":"c03_fc10","question":"What are components of the 'Breathing' step in ABCDE?","answer":"Rate, effort, breath sounds, and oxygen saturation.","category":"Primary Assessment"},{"id":"c03_fc11","question":"Where should a provider look for depth on cardiac-arrest-specific ABCDE content?","answer":"The PALS reviewer — PEPP's ABCDE is a field assessment/transport-decision tool, not a resuscitation-team algorithm.","category":"Cross-Reference"},{"id":"c03_fc12","question":"Why should priority be reassessed throughout the encounter?","answer":"New findings can emerge as the exam and treatment proceed, changing the acuity picture.","category":"Assessment"},{"id":"c03_fc13","question":"Why involve a calm caregiver early in the scene, when safe?","answer":"It often improves both scene safety and the child's cooperation during assessment.","category":"Scene Size-Up"}]},"c04":{"chapter":"c04","cards":[{"id":"c04_fc01","question":"What does the SAMPLE history mnemonic stand for?","answer":"Signs/Symptoms, Allergies, Medications, Past medical history, Last oral intake, Events leading up to the incident.","category":"History"},{"id":"c04_fc02","question":"What pediatric-specific elements are added to SAMPLE?","answer":"Birth history and developmental milestones (infants), immunization status, and growth/weight trends for dosing.","category":"History"},{"id":"c04_fc03","question":"Who should be asked directly for history whenever possible?","answer":"School-age children and adolescents — caregiver accounts should supplement, not replace, the child's own report.","category":"History"},{"id":"c04_fc04","question":"What exam order is preferred for infants and toddlers?","answer":"Toe-to-head — starting with less threatening areas improves cooperation.","category":"Secondary Assessment"},{"id":"c04_fc05","question":"What exam order is typically used for school-age children and adolescents?","answer":"Standard head-to-toe sequence.","category":"Secondary Assessment"},{"id":"c04_fc06","question":"What is family-centered care?","answer":"Treating the caregiver as a partner in the child's care, including allowing presence during many procedures and even resuscitation with a support person.","category":"Family-Centered Care"},{"id":"c04_fc07","question":"Does keeping a caregiver present typically slow down care?","answer":"No — it usually reduces the child's distress and improves cooperation without meaningfully slowing care.","category":"Family-Centered Care"},{"id":"c04_fc08","question":"How should you communicate with a family that doesn't speak English?","answer":"Use professional interpretation services rather than relying on a child to interpret for their own care.","category":"Communication"},{"id":"c04_fc09","question":"How should you approach a child with developmental delay or autism spectrum differences?","answer":"Take cues from the caregiver about the child's usual communication style, minimize sensory overload, and allow extra time.","category":"Communication"},{"id":"c04_fc10","question":"How should you communicate with a hearing-impaired child or caregiver?","answer":"Face them directly, speak clearly (not necessarily loudly), and use written notes or interpreter services as needed.","category":"Communication"},{"id":"c04_fc11","question":"What is the focused exam used for?","answer":"A targeted exam for stable/low-priority patients, directed at the chief complaint.","category":"Secondary Assessment"},{"id":"c04_fc12","question":"What is the rapid exam used for?","answer":"A more limited exam for high-priority patients, often performed en route to the hospital.","category":"Secondary Assessment"},{"id":"c04_fc13","question":"What four steps make up PEPP's complete assessment sequence?","answer":"PAT, primary assessment, history, secondary assessment.","category":"Assessment"},{"id":"c04_fc14","question":"Why is adapting communication considered a clinical skill rather than a courtesy?","answer":"It materially affects the quality of the history and exam obtained, directly impacting patient care.","category":"Communication"}]},"c05":{"chapter":"c05","cards":[{"id":"c05_fc01","question":"What is respiratory distress?","answer":"A state where a child is working hard to breathe (increased work of breathing) but is still compensating, generally with adequate oxygenation and mental status.","category":"Respiratory"},{"id":"c05_fc02","question":"What is respiratory failure?","answer":"A state where compensation has failed — inadequate oxygenation and/or ventilation, marked by altered mental status, cyanosis, bradypnea/irregular breathing, and profound fatigue.","category":"Respiratory"},{"id":"c05_fc03","question":"What are the four categories of pediatric respiratory compromise?","answer":"Upper airway obstruction, lower airway disease, lung tissue (parenchymal) disease, and disordered control of breathing.","category":"Respiratory"},{"id":"c05_fc04","question":"What sound is classically associated with upper airway obstruction?","answer":"Stridor.","category":"Respiratory"},{"id":"c05_fc05","question":"What sound is classically associated with lower airway disease?","answer":"Wheezing, with prolonged expiration.","category":"Respiratory"},{"id":"c05_fc06","question":"What findings are classically associated with lung tissue (parenchymal) disease?","answer":"Grunting, crackles, and diminished breath sounds.","category":"Respiratory"},{"id":"c05_fc07","question":"What characterizes disordered control of breathing?","answer":"An irregular rate/pattern without the classic sounds of the other three categories, often from a CNS problem, toxin, or neuromuscular disease.","category":"Respiratory"},{"id":"c05_fc08","question":"Give two examples of causes of upper airway obstruction.","answer":"Croup and foreign body aspiration (also epiglottitis).","category":"Respiratory"},{"id":"c05_fc09","question":"Give two examples of causes of lower airway disease.","answer":"Asthma and bronchiolitis.","category":"Respiratory"},{"id":"c05_fc10","question":"Why is decreasing work of breathing in a previously struggling child a red flag?","answer":"It can reflect exhaustion rather than improvement — a dangerous, easily misread sign of impending respiratory failure.","category":"Respiratory"},{"id":"c05_fc11","question":"What PAT change signals impending respiratory failure?","answer":"A shift in Appearance from anxious/agitated to lethargic on repeat assessment.","category":"Respiratory"},{"id":"c05_fc12","question":"Should a provider wait for SpO2 to fall before escalating support in a deteriorating child?","answer":"No — other findings (grunting, decreasing WOB after struggling, altered Appearance) often precede a measurable drop in SpO2 and should prompt escalation first.","category":"Respiratory"},{"id":"c05_fc13","question":"What is the field management for respiratory distress?","answer":"Positioning of comfort, supplemental oxygen, and treatment targeted to the likely category (e.g., nebulized bronchodilator for suspected lower-airway disease), with close monitoring.","category":"Field Management"},{"id":"c05_fc14","question":"What is the field management for respiratory failure?","answer":"Assisted ventilation with bag-mask ventilation and high-flow oxygen, plus rapid transport; drug-assisted airway management and arrest-specific ventilation are covered in depth by the PALS reviewer.","category":"Field Management"},{"id":"c05_fc15","question":"Why do respiratory problems matter so much in pediatric prehospital care?","answer":"They are the leading pathway to pediatric cardiac arrest, unlike adults where a primary cardiac event is more common.","category":"Respiratory"}]},"c06":{"chapter":"c06","cards":[{"id":"c06_fc01","question":"How is shock best defined?","answer":"Inadequate delivery of oxygen and nutrients to meet tissue demands — a perfusion problem, not a specific blood pressure value.","category":"Shock"},{"id":"c06_fc02","question":"Can a child be in shock with a normal blood pressure?","answer":"Yes — this is compensated shock; children compensate well via tachycardia and vasoconstriction, keeping BP normal until late.","category":"Shock"},{"id":"c06_fc03","question":"What does hypotension mean in a pediatric shock patient?","answer":"It signals decompensated shock — a late, ominous sign meaning compensatory mechanisms have been exhausted.","category":"Shock"},{"id":"c06_fc04","question":"List the perfusion findings used to recognize compensated shock.","answer":"Tachycardia, delayed capillary refill, abnormal skin color/temperature (cool/mottled or warm/flushed), weak/narrowed pulses, narrowed pulse pressure.","category":"Shock"},{"id":"c06_fc05","question":"What are the four major categories of pediatric shock?","answer":"Hypovolemic, distributive, cardiogenic, and obstructive.","category":"Shock"},{"id":"c06_fc06","question":"What is the most common category of shock in children overall?","answer":"Hypovolemic shock (from fluid or blood loss, e.g., dehydration, hemorrhage, burns).","category":"Shock"},{"id":"c06_fc07","question":"Name three types of distributive shock.","answer":"Septic shock, anaphylactic shock, and neurogenic shock (rare in children).","category":"Shock"},{"id":"c06_fc08","question":"What causes cardiogenic shock in children?","answer":"Pump failure from congenital heart disease, myocarditis, or arrhythmia.","category":"Shock"},{"id":"c06_fc09","question":"What causes obstructive shock?","answer":"A physical obstruction to blood flow, such as tension pneumothorax, cardiac tamponade, or massive pulmonary embolism (rare in children).","category":"Shock"},{"id":"c06_fc10","question":"How might early septic (distributive) shock differ in appearance from hypovolemic shock?","answer":"Early septic shock can present with warm, flushed skin and bounding pulses (rather than cold/mottled skin), despite poor perfusion.","category":"Shock"},{"id":"c06_fc11","question":"What PAT findings suggest shock?","answer":"Abnormal Appearance (irritability progressing to lethargy) and/or abnormal Circulation to Skin (pallor, mottling, cyanosis), often with normal-appearing work of breathing.","category":"Shock"},{"id":"c06_fc12","question":"What is the priority field treatment for suspected anaphylactic shock?","answer":"Epinephrine.","category":"Field Management"},{"id":"c06_fc13","question":"What is the priority field treatment for suspected obstructive shock from tension pneumothorax?","answer":"Needle decompression per protocol/scope of practice.","category":"Field Management"},{"id":"c06_fc14","question":"What is the general supportive field management for shock regardless of category?","answer":"Supplemental oxygen, positioning (supine, legs elevated if tolerated), keep the child warm, and rapid transport.","category":"Field Management"},{"id":"c06_fc15","question":"Where should providers look for drug dosing tables and advanced shock/arrest resuscitation algorithms?","answer":"The PALS reviewer — PEPP covers field recognition and initial stabilization only.","category":"Field Management"}]},"c07":{"chapter":"c07","cards":[{"id":"c07_fc01","question":"Are primary cardiac events common in children?","answer":"No — unlike adults, primary cardiac disease is a rare cause of pediatric emergencies; most cardiac problems are secondary.","category":"Cardiac"},{"id":"c07_fc02","question":"What is the most common cause of pediatric bradycardia?","answer":"Hypoxia.","category":"Cardiac"},{"id":"c07_fc03","question":"Besides hypoxia, what else can cause pediatric bradycardia?","answer":"Increased vagal tone, hypothermia, or increased intracranial pressure.","category":"Cardiac"},{"id":"c07_fc04","question":"What is the field priority for symptomatic bradycardia in a child?","answer":"Address the underlying cause — oxygenate and ventilate first — rather than treating the rhythm number alone.","category":"Cardiac"},{"id":"c07_fc05","question":"How does sinus tachycardia typically behave?","answer":"It is a compensatory response (fever, pain, anxiety, dehydration, shock) with a variable rate that resolves as the underlying cause is treated.","category":"Cardiac"},{"id":"c07_fc06","question":"How does supraventricular tachycardia (SVT) typically behave?","answer":"It is a primary rhythm disturbance with a fixed, very rapid rate that does not vary with stimulation and can itself cause poor perfusion.","category":"Cardiac"},{"id":"c07_fc07","question":"What infant heart rate threshold is often used to raise suspicion for SVT?","answer":">220 bpm in infants (compared to >180 bpm in older children), as a fixed rate not varying with stimulation.","category":"Cardiac"},{"id":"c07_fc08","question":"Why should a provider ask about a child's known congenital heart disease?","answer":"Because such children may have a baseline vital signs or oxygen saturation that differs from typical pediatric norms, and are at elevated risk for arrhythmia, heart failure, and cardiogenic shock.","category":"Cardiac"},{"id":"c07_fc09","question":"What family history clue raises suspicion for an underlying cardiac cause of unexplained pediatric collapse?","answer":"Sudden unexplained death in a young relative (suggesting a possible cardiac channelopathy).","category":"Cardiac"},{"id":"c07_fc10","question":"What are the field priorities for a pediatric cardiac emergency?","answer":"Recognition (PAT + primary assessment + monitor/rhythm strip if available), identifying reversible causes (especially hypoxia), and rapid transport with continuous reassessment.","category":"Field Management"},{"id":"c07_fc11","question":"Does this PEPP chapter cover arrest algorithms and antiarrhythmic drug dosing in depth?","answer":"No — those are covered in full depth by the PALS reviewer; this chapter covers field recognition and initial stabilization only.","category":"Field Management"},{"id":"c07_fc12","question":"What is a poor-perfusion bradycardic infant most likely to represent until proven otherwise?","answer":"A respiratory or hypoxia problem, not a primary cardiac rhythm problem.","category":"Cardiac"}]},"c08":{"chapter":"c08","cards":[{"id":"c08_fc01","question":"What PAT leg often gives the first clue to altered mental status?","answer":"Appearance (e.g., poor eye contact, abnormal cry, decreased interactiveness).","category":"Neurologic"},{"id":"c08_fc02","question":"What does AVPU stand for?","answer":"Alert, Voice, Pain, Unresponsive.","category":"Neurologic"},{"id":"c08_fc03","question":"What does the AEIOU-TIPS mnemonic help recall?","answer":"Reversible causes of altered mental status: Alcohol/substance, Epilepsy/postictal, Infection, Overdose, Uremia/metabolic, Trauma/temperature, Insulin/hypoglycemia, Psychiatric, Shock/stroke.","category":"Neurologic"},{"id":"c08_fc04","question":"Why should every altered child get a glucose check when available?","answer":"Hypoglycemia is a common, rapidly reversible cause of altered mental status in children.","category":"Neurologic"},{"id":"c08_fc05","question":"What are the field priorities during an active pediatric seizure?","answer":"Protect the airway (positioning, suction as needed, nothing in the mouth), protect from injury, check glucose, and time the seizure.","category":"Seizures"},{"id":"c08_fc06","question":"What defines status epilepticus?","answer":"A seizure lasting more than 5 minutes, or repeated seizures without return to baseline between them.","category":"Seizures"},{"id":"c08_fc07","question":"Is status epilepticus a time-critical emergency?","answer":"Yes — it requires rapid escalation of care and transport; benzodiazepine dosing is detailed in the PALS reviewer.","category":"Seizures"},{"id":"c08_fc08","question":"What age range is most typical for febrile seizures?","answer":"6 months to 5 years, with a rapidly rising fever.","category":"Seizures"},{"id":"c08_fc09","question":"What defines a simple febrile seizure?","answer":"Generalized, lasts less than 15 minutes, does not recur within 24 hours, and the child returns to baseline mental status afterward.","category":"Seizures"},{"id":"c08_fc10","question":"What defines a complex febrile seizure?","answer":"Focal features, lasting more than 15 minutes, or recurring within 24 hours — warrants a higher level of concern.","category":"Seizures"},{"id":"c08_fc11","question":"What are signs suggesting increased intracranial pressure in an infant?","answer":"A bulging fontanelle, decreasing level of consciousness, and an irregular respiratory pattern.","category":"Neurologic"},{"id":"c08_fc12","question":"What is the Cushing triad?","answer":"Hypertension, bradycardia, and irregular respirations — a late and ominous sign of increased intracranial pressure.","category":"Neurologic"},{"id":"c08_fc13","question":"What two physiologic states should be avoided in a child with suspected increased intracranial pressure, and why?","answer":"Hypoxia and hypotension — both worsen secondary brain injury.","category":"Neurologic"},{"id":"c08_fc14","question":"Should a trend of decreasing responsiveness on serial reassessment be treated as more or less concerning than a single snapshot?","answer":"More concerning — trends over time matter more than a single value.","category":"Neurologic"}]}},"quizzes":{"c01":{"chapter":"c01","questions":[{"id":"c01_q01","question":"What is the core organizing principle of PEPP's approach to pediatric patients?","options":["A. Children should be treated with scaled-down adult protocols","B. Children differ from adults anatomically, physiologically, developmentally, and psychosocially — not just in size","C. Pediatric care is identical to adult care below a certain weight threshold","D. Only infants require a different assessment approach"],"correct":1,"rationale":"PEPP's foundational premise is that children are not small adults — differences span anatomy, physiology, development, and psychosocial needs, requiring a distinct approach at every stage of care.","difficulty":"Easy"},{"id":"c01_q02","question":"Where is the narrowest point of a young child's airway located?","options":["A. At the vocal cords, same as adults","B. Subglottic, below the vocal cords","C. At the nostrils","D. At the epiglottis only"],"correct":1,"rationale":"Unlike adults, whose airway narrows at the vocal cords, a young child's airway is narrowest below the cords (subglottic), an important anatomic difference for airway management.","difficulty":"Medium"},{"id":"c01_q03","question":"Why do children desaturate faster than adults when breathing is compromised?","options":["A. They have larger oxygen reserves","B. Higher metabolic rate/oxygen consumption combined with smaller functional residual capacity","C. They breathe more slowly than adults","D. Their chest walls are stiffer than adults'"],"correct":1,"rationale":"Children consume more oxygen per kilogram than adults but have less reserve capacity in the lungs, so oxygenation drops faster when ventilation is impaired.","difficulty":"Medium"},{"id":"c01_q04","question":"What is the leading pathway to cardiac arrest in children, distinct from adults?","options":["A. Primary cardiac dysrhythmia","B. Respiratory problems","C. Toxic ingestion","D. Congenital heart disease in all cases"],"correct":1,"rationale":"Unlike adults where primary cardiac events predominate, pediatric arrest is most often the end result of progressive respiratory failure or shock.","difficulty":"Easy"},{"id":"c01_q05","question":"Why is blood pressure considered a late and unreliable early sign of shock in children?","options":["A. Children cannot mount a compensatory response","B. Children compensate well via tachycardia and vasoconstriction, maintaining normal BP until significant volume is lost","C. Blood pressure is always elevated in pediatric shock","D. Children's blood pressure cannot be measured accurately"],"correct":1,"rationale":"Robust compensatory mechanisms keep blood pressure normal-appearing until a substantial percentage of circulating volume is lost, making BP a poor early screening tool in children.","difficulty":"Medium"},{"id":"c01_q06","question":"What happens once a child's shock compensation fails?","options":["A. Gradual, well-tolerated decline","B. Rapid decompensation with little warning","C. Spontaneous recovery","D. No change in clinical status"],"correct":1,"rationale":"Because compensation in children is so effective until it isn't, decompensation — once it begins — tends to occur rapidly, giving little advance warning.","difficulty":"Medium"},{"id":"c01_q07","question":"What is the best approach to assessing a frightened toddler?","options":["A. Separate the child from caregivers immediately for an accurate exam","B. Keep the caregiver close and demonstrate equipment on a doll or the caregiver first","C. Use complex medical terminology to build trust","D. Approach with unfamiliar equipment first to desensitize the child"],"correct":1,"rationale":"Toddlers fear separation and unfamiliar equipment; keeping caregivers close and demonstrating equipment first reduces distress and improves cooperation and assessment accuracy.","difficulty":"Easy"},{"id":"c01_q08","question":"What is the best approach to interviewing an adolescent patient?","options":["A. Always keep a parent present for every question","B. Provide privacy, respect, and honesty, considering some interview time apart from caregivers","C. Speak only to the caregiver, not the patient","D. Use the same approach as with a toddler"],"correct":1,"rationale":"Adolescents value privacy, respect, and direct honesty, and may disclose more accurately when interviewed partly apart from caregivers.","difficulty":"Easy"},{"id":"c01_q09","question":"Why is a single 'normal vital signs' reference not useful in pediatrics?","options":["A. Vital signs don't matter in children","B. Normal heart rate, respiratory rate, and blood pressure vary substantially across pediatric age bands","C. Pediatric vital signs cannot be measured in the field","D. All children have identical vital signs regardless of age"],"correct":1,"rationale":"Because normal ranges shift significantly from neonate through adolescent, every vital sign must be compared against an age-appropriate reference range.","difficulty":"Easy"},{"id":"c01_q10","question":"What matters more than a single isolated vital sign reading in pediatric assessment?","options":["A. The exact numeric value alone","B. Trends over time and the overall clinical picture (e.g., the Pediatric Assessment Triangle)","C. Only the respiratory rate","D. The child's stated pain level alone"],"correct":1,"rationale":"A single vital sign can be misleading in isolation; trends and the broader clinical gestalt provide more reliable information about the child's true status.","difficulty":"Medium"},{"id":"c01_q11","question":"Why does a modest-seeming blood loss matter more in a child than in an adult?","options":["A. Children have larger total blood volumes","B. A child's absolute circulating blood volume is small, so the same loss is a larger percentage of total volume","C. Children's blood clots more slowly","D. This is not actually true — losses are equivalent"],"correct":1,"rationale":"Because total circulating volume is smaller in children, an amount of blood loss that would be minor in an adult can represent a much larger fraction of a child's total volume.","difficulty":"Medium"},{"id":"c01_q12","question":"How does the pediatric larynx position differ anatomically from an adult's?","options":["A. More posterior and lower","B. More anterior and cephalad (higher)","C. Identical position","D. Absent in infants"],"correct":1,"rationale":"The pediatric larynx sits more anterior and cephalad than the adult larynx, an important consideration for airway positioning and visualization.","difficulty":"Medium"},{"id":"c01_q13","question":"Why are infants at particular risk of fatigue during increased work of breathing?","options":["A. They have highly rigid chest walls","B. They are diaphragmatic breathers with a compliant chest wall, generating less effective negative pressure and fatiguing faster","C. Infants never show signs of respiratory distress","D. Infant lungs have unusually large reserve capacity"],"correct":1,"rationale":"The compliant infant chest wall and diaphragm-dependent breathing generate less effective ventilatory force, so infants tire more quickly when working hard to breathe.","difficulty":"Hard"},{"id":"c01_q14","question":"A provider uses an adult mental model unmodified when assessing an infant's airway. What is the risk?","options":["A. No risk — pediatric and adult airways are identical","B. Missing anatomic differences (large tongue, anterior/cephalad larynx, subglottic narrowing) that change positioning and equipment needs","C. Improved outcomes from consistency","D. The risk only applies to children over age 10"],"correct":1,"rationale":"Anatomic differences unique to the pediatric airway change how it should be assessed and managed; applying an unmodified adult model risks missing or mismanaging obstruction.","difficulty":"Hard"}]},"c02":{"chapter":"c02","questions":[{"id":"c02_q01","question":"What are the three legs of the Pediatric Assessment Triangle?","options":["A. Airway, Breathing, Circulation","B. Appearance, Work of Breathing, Circulation to Skin","C. History, Exam, Vital Signs","D. Tone, Color, Cry"],"correct":1,"rationale":"The PAT's three legs are Appearance, Work of Breathing, and Circulation to Skin — assessed together from across the room before any hands-on contact.","difficulty":"Easy"},{"id":"c02_q02","question":"What does the TICLS mnemonic help assess?","options":["A. Work of Breathing","B. Circulation to Skin","C. Appearance","D. Vital signs"],"correct":2,"rationale":"TICLS (Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry) breaks down the Appearance leg of the PAT into observable components.","difficulty":"Easy"},{"id":"c02_q03","question":"A child is limp, will not make eye contact, and is inconsolable, but breathing appears effortless and skin color is normal. What does this pattern suggest?","options":["A. A respiratory problem","B. A primarily CNS/metabolic problem","C. A shock/circulatory problem","D. Cardiopulmonary failure"],"correct":1,"rationale":"Abnormal Appearance alone, with normal Work of Breathing and Circulation, points toward a CNS/metabolic category rather than a respiratory or circulatory problem.","difficulty":"Medium"},{"id":"c02_q04","question":"A child has abnormal Appearance (lethargic) AND visible retractions with nasal flaring, but normal skin color. What is the likely category?","options":["A. CNS/metabolic problem","B. Respiratory problem","C. Shock","D. Cardiopulmonary failure"],"correct":1,"rationale":"Abnormal Appearance combined with abnormal Work of Breathing (retractions, flaring), with normal circulation, points to a respiratory category.","difficulty":"Medium"},{"id":"c02_q05","question":"A child is lethargic and has mottled, cool skin, but breathing appears unlabored with no retractions. What is the likely category?","options":["A. Respiratory problem","B. Shock/circulatory problem","C. Normal finding","D. Isolated CNS problem only"],"correct":1,"rationale":"Abnormal Appearance plus abnormal Circulation to Skin, with normal Work of Breathing, suggests a shock/circulatory category.","difficulty":"Medium"},{"id":"c02_q06","question":"A child shows abnormal findings across ALL three PAT legs. What does this represent?","options":["A. A mild, self-limited illness","B. Cardiopulmonary failure — the highest-urgency category","C. Normal variation","D. An isolated skin condition"],"correct":1,"rationale":"Abnormality across all three legs indicates a severe, multi-system problem — cardiopulmonary failure — requiring the most urgent response.","difficulty":"Medium"},{"id":"c02_q07","question":"Is the PAT performed with a stethoscope or blood pressure cuff?","options":["A. Yes, both are required","B. No — it is entirely hands-off, visual and auditory, from across the room","C. Only a stethoscope is used","D. Only a BP cuff is used"],"correct":1,"rationale":"The PAT is deliberately hands-off, performed by observation and listening from a distance before any equipment or touching begins.","difficulty":"Easy"},{"id":"c02_q08","question":"A child looks well on the PAT. What should the provider do next?","options":["A. Skip the primary assessment since the PAT was reassuring","B. Proceed to a full hands-on primary assessment at a calmer pace","C. Discharge the patient immediately","D. Only check vital signs, skip any exam"],"correct":1,"rationale":"The PAT never replaces the hands-on primary assessment — a reassuring PAT sets a calmer pace, but the full ABCDE assessment still follows.","difficulty":"Easy"},{"id":"c02_q09","question":"Why is Work of Breathing considered an 'early window' into respiratory status?","options":["A. It only becomes abnormal after the child has already desaturated","B. Increased effort reflects compensation and can appear before oxygen saturation falls","C. It has no relationship to oxygenation","D. It is only useful in adults"],"correct":1,"rationale":"Increased work of breathing is a compensatory response that often precedes a measurable drop in SpO2, making it an early indicator of respiratory compromise.","difficulty":"Medium"},{"id":"c02_q10","question":"Which finding is part of the Circulation to Skin leg of the PAT?","options":["A. Retractions","B. Nasal flaring","C. Mottling","D. Stridor"],"correct":2,"rationale":"Mottling is a skin-color finding assessed under Circulation to Skin; retractions, flaring, and stridor belong to the Work of Breathing leg.","difficulty":"Easy"},{"id":"c02_q11","question":"Why is Appearance considered the most sensitive PAT leg?","options":["A. It is the easiest to measure with equipment","B. It reflects the adequacy of oxygenation, ventilation, brain perfusion, and CNS function all at once","C. It is only relevant in trauma","D. It replaces the need for the other two legs"],"correct":1,"rationale":"Appearance integrates multiple physiologic systems, making it a highly sensitive early indicator — an abnormal Appearance is a red flag even if the other two legs look normal.","difficulty":"Medium"},{"id":"c02_q12","question":"What is meant by assessing the PAT 'from the doorway'?","options":["A. Only assessing patients who are near an actual doorway","B. The PAT is completed within the first seconds of encountering the child, before approaching or touching them","C. The PAT requires the child to be standing in a doorway","D. This phrase has no specific meaning in PEPP"],"correct":1,"rationale":"The 'from the doorway' framing captures how quickly and unobtrusively the PAT is performed — a rapid visual/auditory read taken immediately upon encountering the child.","difficulty":"Medium"},{"id":"c02_q13","question":"A muffled, weak cry in an infant is a finding under which PAT leg?","options":["A. Work of Breathing","B. Circulation to Skin","C. Appearance (Speech/Cry component of TICLS)","D. None of the legs"],"correct":2,"rationale":"Speech/Cry is one of the five TICLS components under the Appearance leg; a weak or muffled cry is an abnormal Appearance finding.","difficulty":"Medium"},{"id":"c02_q14","question":"Why does the PAT drive 'the pace of everything that follows' rather than the content of care?","options":["A. It determines drug doses directly","B. It sets the general impression and urgency level, shaping how quickly the primary assessment proceeds and whether interventions happen simultaneously","C. It has no influence on subsequent care","D. It replaces vital sign measurement entirely"],"correct":1,"rationale":"The PAT's purpose is to establish urgency and likely category quickly, which shapes the speed and sequencing of the ensuing primary assessment and interventions — not to dictate specific treatments by itself.","difficulty":"Hard"},{"id":"c02_q15","question":"Which combination of PAT findings would most strongly suggest the HIGHEST acuity requiring the most urgent response?","options":["A. Normal Appearance, normal Work of Breathing, normal Circulation","B. Abnormal Appearance, Work of Breathing, AND Circulation to Skin all together","C. Mild nasal flaring only, otherwise normal","D. Slightly pale skin with normal Appearance and breathing"],"correct":1,"rationale":"Abnormalities across all three PAT legs together represent the cardiopulmonary failure category, the highest-urgency PAT pattern.","difficulty":"Medium"},{"id":"c02_q16","question":"How should skin color findings under Circulation to Skin be interpreted?","options":["A. Against a universal standard regardless of the individual child","B. Against the child's own baseline skin tone, in adequate lighting","C. Only cyanosis matters; pallor and mottling are irrelevant","D. Skin color cannot be reliably assessed in the field"],"correct":1,"rationale":"Skin findings are compared to the individual child's baseline tone under good lighting, since a fixed universal standard would not account for normal variation between children.","difficulty":"Medium"}]},"c03":{"chapter":"c03","questions":[{"id":"c03_q01","question":"What does the pediatric primary assessment sequence ABCDE stand for?","options":["A. Appearance, Breathing, Color, Development, Exam","B. Airway, Breathing, Circulation, Disability, Exposure","C. Assessment, Baseline, Care, Documentation, Evaluation","D. Alertness, Body, Chest, Digits, Extremities"],"correct":1,"rationale":"The pediatric primary assessment follows the ABCDE sequence: Airway, Breathing, Circulation, Disability, Exposure — the same spine used across PALS and PEPP.","difficulty":"Easy"},{"id":"c03_q02","question":"During the primary assessment, you find an obstructed airway while assessing 'A'. What should you do?","options":["A. Note it and continue through B, C, D, E first","B. Treat the airway obstruction immediately before proceeding","C. Wait until the secondary assessment to address it","D. Only address it if breathing is also abnormal"],"correct":1,"rationale":"Life threats found at any step of ABCDE are treated immediately, not deferred until the full sequence is complete.","difficulty":"Easy"},{"id":"c03_q03","question":"What is assessed under the 'Disability' step of pediatric ABCDE?","options":["A. Skin color only","B. Rapid neurologic status (e.g., AVPU), pupils, and glucose if altered","C. Chest wall retractions","D. External hemorrhage"],"correct":1,"rationale":"Disability covers a rapid neurologic check, pupillary assessment, and blood glucose measurement when mental status is altered.","difficulty":"Easy"},{"id":"c03_q04","question":"What is the primary assessment's main deliverable?","options":["A. A specific final diagnosis","B. An overall priority decision (high vs. low acuity)","C. A completed transport report","D. A medication administration record"],"correct":1,"rationale":"The primary assessment concludes with a priority determination that drives the pace of subsequent care, rather than a definitive diagnosis.","difficulty":"Medium"},{"id":"c03_q05","question":"How does a high-acuity PAT (e.g., cardiopulmonary failure pattern) change how the primary assessment proceeds?","options":["A. It has no effect on the primary assessment","B. The primary assessment proceeds immediately and rapidly, often with simultaneous interventions","C. The primary assessment is skipped entirely","D. Only the Exposure step is performed"],"correct":1,"rationale":"A high-acuity PAT sets urgency, prompting rapid primary assessment with interventions occurring simultaneously rather than in strict sequence.","difficulty":"Medium"},{"id":"c03_q06","question":"Which additional considerations are part of pediatric scene size-up beyond standard safety and precautions?","options":["A. Only the child's exact age in months","B. Mechanism/nature of illness, patient count, and environmental clues","C. Only the caregiver's insurance information","D. Nothing additional beyond adult scene size-up"],"correct":1,"rationale":"Pediatric scene size-up adds attention to mechanism/nature of illness, potential multiple patients, and environmental clues (medications, hazards, caregiver affect).","difficulty":"Medium"},{"id":"c03_q07","question":"A reassuring PAT is obtained. Should the primary assessment still be performed?","options":["A. No, it can be skipped","B. Yes — the PAT sets pace, it does not replace the hands-on ABCDE exam","C. Only if the caregiver requests it","D. Only for children under 1 year old"],"correct":1,"rationale":"The PAT never substitutes for the primary assessment; a reassuring PAT simply allows the exam to proceed at a calmer pace.","difficulty":"Easy"},{"id":"c03_q08","question":"What is assessed under 'Circulation' in pediatric ABCDE?","options":["A. Pupil size only","B. Pulse rate/quality, skin perfusion, capillary refill, and external bleeding","C. Respiratory rate","D. Level of consciousness"],"correct":1,"rationale":"Circulation assessment covers pulse characteristics, perfusion indicators like capillary refill and skin, and control of external hemorrhage.","difficulty":"Easy"},{"id":"c03_q09","question":"Where should a provider look for cardiac-arrest-specific ABCDE depth beyond field recognition?","options":["A. The PEPP reviewer alone covers this fully","B. The PALS reviewer","C. The BDLS reviewer","D. No resource covers this"],"correct":1,"rationale":"PEPP frames ABCDE as a field assessment/transport-decision tool; resuscitation-team algorithm depth is intentionally deferred to the PALS reviewer to avoid duplicating or contradicting it.","difficulty":"Medium"},{"id":"c03_q10","question":"What should happen to the priority decision as new findings emerge during the encounter?","options":["A. It should never change once set","B. It should be reassessed and updated as new information becomes available","C. Priority is only assigned at the very end of the call","D. Priority does not affect subsequent care"],"correct":1,"rationale":"Priority is not a one-time determination; it should be reassessed as the exam, treatment, and reassessment reveal new findings.","difficulty":"Medium"},{"id":"c03_q11","question":"What is assessed under the 'Exposure' step of ABCDE?","options":["A. Blood glucose","B. Undressing as needed to check for injury/rash, then keeping the child warm","C. Airway patency","D. Pupil reactivity"],"correct":1,"rationale":"Exposure involves assessing the body for injury or rash by undressing as clinically indicated, followed by re-covering the child to prevent heat loss.","difficulty":"Easy"},{"id":"c03_q12","question":"A child has abnormal breath sounds found during the 'B' step. What is the correct action?","options":["A. Continue to 'C' and address breathing at the end","B. Address the breathing problem immediately before continuing","C. Only address it during the secondary assessment","D. Ignore it if the PAT appeared reassuring"],"correct":1,"rationale":"Any abnormal or life-threatening finding at a given ABCDE step is treated immediately rather than deferred, regardless of the preceding PAT impression.","difficulty":"Medium"},{"id":"c03_q13","question":"Why is patient count an important scene size-up consideration in pediatric calls specifically?","options":["A. Children are never involved in multi-victim events","B. Children are frequently involved in multi-victim events (e.g., car crashes, household incidents)","C. Only adult patient counts matter for resource allocation","D. This consideration is unique to adult scenes"],"correct":1,"rationale":"Pediatric events often involve multiple patients (e.g., siblings in a car crash), making early patient-count assessment operationally important.","difficulty":"Medium"},{"id":"c03_q14","question":"Which best describes the relationship between the PAT and primary assessment as a two-step process?","options":["A. They are identical and redundant","B. The PAT is hands-off and sets urgency/pace; the primary assessment is the hands-on ABCDE exam that follows and is never skipped","C. The primary assessment always comes first","D. Only one of the two is ever performed per patient"],"correct":1,"rationale":"The PAT and primary assessment are sequential, complementary steps — the PAT's hands-off impression sets the tone, and the hands-on ABCDE exam always follows.","difficulty":"Hard"}]},"c04":{"chapter":"c04","questions":[{"id":"c04_q01","question":"What does the SAMPLE history mnemonic stand for?","options":["A. Signs/Symptoms, Allergies, Medications, Past history, Last intake, Events","B. Scene, Assessment, Monitoring, Priority, Location, Evaluation","C. Safety, Airway, Motion, Perfusion, Life threats, Exposure","D. Support, Attitude, Medication, Prognosis, Location, Escalation"],"correct":0,"rationale":"SAMPLE stands for Signs/Symptoms, Allergies, Medications, Past medical history, Last oral intake, and Events leading up to the incident.","difficulty":"Easy"},{"id":"c04_q02","question":"What pediatric-specific elements are added to the standard SAMPLE history?","options":["A. Employment history","B. Birth history/developmental milestones, immunization status, and growth/weight trends","C. Credit history","D. Nothing is added for children"],"correct":1,"rationale":"Pediatric SAMPLE histories add emphasis on birth/developmental history for infants, immunization status, and growth/weight trends relevant to medication dosing.","difficulty":"Medium"},{"id":"c04_q03","question":"Who should be asked directly about their symptoms whenever possible?","options":["A. Only caregivers, never the child","B. School-age children and adolescents, with caregiver accounts supplementing rather than replacing their report","C. Only infants","D. No one should be asked directly; observation alone suffices"],"correct":1,"rationale":"Older children and adolescents can usually provide reliable direct history, and their own report should be sought and supplemented (not replaced) by caregiver information.","difficulty":"Medium"},{"id":"c04_q04","question":"Which exam order is preferred for a frightened toddler?","options":["A. Head-to-toe","B. Toe-to-head","C. Random order","D. Only auscultation, no other exam"],"correct":1,"rationale":"Starting with less threatening body areas (toe-to-head) improves cooperation in young, frightened children compared to the standard head-to-toe order.","difficulty":"Easy"},{"id":"c04_q05","question":"Which exam order is typically appropriate for a cooperative school-age child or adolescent?","options":["A. Toe-to-head only","B. Standard head-to-toe sequence","C. No physical exam is needed","D. Only exam areas the child requests"],"correct":1,"rationale":"Older, more cooperative children can typically tolerate the standard head-to-toe exam sequence used in adult care.","difficulty":"Easy"},{"id":"c04_q06","question":"What is family-centered care?","options":["A. Excluding caregivers from all pediatric encounters","B. Treating the caregiver as a partner in the child's care, including presence during many procedures","C. Allowing caregivers to make all treatment decisions without provider input","D. A billing category unrelated to clinical practice"],"correct":1,"rationale":"Family-centered care partners with caregivers rather than excluding them, recognizing their presence typically benefits the child without meaningfully slowing care.","difficulty":"Easy"},{"id":"c04_q07","question":"Does allowing a caregiver to remain present during care typically slow things down?","options":["A. Yes, significantly","B. No — it usually reduces distress and improves cooperation without meaningfully slowing care","C. Only for infants","D. Only during transport, never during assessment"],"correct":1,"rationale":"Family-centered care research and practice support that caregiver presence generally improves the encounter without materially delaying care.","difficulty":"Medium"},{"id":"c04_q08","question":"A family does not speak English. What is the correct approach to communication?","options":["A. Have the child interpret for their caregiver","B. Use professional interpretation services","C. Speak louder in English","D. Skip history-taking entirely"],"correct":1,"rationale":"Relying on a child to interpret medical information places an inappropriate burden on them and risks inaccurate communication; professional interpretation services are the correct approach.","difficulty":"Easy"},{"id":"c04_q09","question":"How should a provider approach a child with autism spectrum differences?","options":["A. Use the identical approach for every patient regardless of the caregiver's input","B. Take cues from the caregiver about the child's usual communication style, minimize sensory overload, and allow extra time","C. Speak only to the caregiver and ignore the child entirely","D. Rush the exam to minimize contact time"],"correct":1,"rationale":"Individualized communication guided by the caregiver, reduced sensory overload, and allowing extra time improve the encounter for children with developmental differences.","difficulty":"Medium"},{"id":"c04_q10","question":"What is the difference between the focused exam and the rapid exam in secondary assessment?","options":["A. They are identical","B. The focused exam targets the chief complaint for stable/low-priority patients; the rapid exam is more limited, for high-priority patients often performed en route","C. The rapid exam is only for infants","D. The focused exam is only used in the hospital"],"correct":1,"rationale":"The secondary assessment adapts to patient priority: a focused exam for stable patients on scene, versus a rapid, more limited exam for high-priority patients, often continued during transport.","difficulty":"Medium"},{"id":"c04_q11","question":"How should a provider communicate with a hearing-impaired caregiver?","options":["A. Speak as loudly as possible from across the room","B. Face them directly, speak clearly, and use written notes or interpreter services as needed","C. Avoid direct communication entirely","D. Only communicate through the child"],"correct":1,"rationale":"Facing the person directly and speaking clearly (not necessarily loudly), supplemented by written notes or interpreter services, is the appropriate communication approach.","difficulty":"Medium"},{"id":"c04_q12","question":"What four steps make up PEPP's complete pediatric assessment sequence?","options":["A. History, exam, transport, documentation","B. PAT, primary assessment, history, secondary assessment","C. Scene safety, vitals, treatment, discharge","D. Appearance, breathing, circulation, disability"],"correct":1,"rationale":"The full PEPP sequence is: Pediatric Assessment Triangle, primary assessment (ABCDE), history-taking, and secondary assessment — each building on the last.","difficulty":"Medium"},{"id":"c04_q13","question":"Why is growth/weight trend information part of a thorough pediatric SAMPLE history?","options":["A. It is irrelevant to prehospital care","B. It informs weight-based medication dosing considerations","C. It is only used for insurance billing","D. It replaces the need for a chief complaint"],"correct":1,"rationale":"Weight/growth information is directly relevant to weight-based dosing considerations that may apply during subsequent care.","difficulty":"Medium"},{"id":"c04_q14","question":"Why is adapting communication for special needs considered a clinical skill rather than an optional courtesy?","options":["A. It has no effect on care quality","B. It materially affects the quality and accuracy of the history and exam obtained","C. It is only relevant for documentation purposes","D. It is required only by hospital policy, not clinical necessity"],"correct":1,"rationale":"Communication adaptation directly impacts how much accurate, useful clinical information a provider can gather — making it a core clinical skill, not a courtesy.","difficulty":"Hard"}]},"c05":{"chapter":"c05","questions":[{"id":"c05_q01","question":"What best distinguishes respiratory distress from respiratory failure?","options":["A. Distress means compensating with adequate oxygenation/mentation; failure means compensation has failed","B. Distress always requires intubation; failure never does","C. Distress only occurs in infants; failure only in adolescents","D. There is no clinical difference"],"correct":0,"rationale":"Respiratory distress is a compensated state (increased work of breathing but adequate oxygenation/mentation); respiratory failure is a decompensated state where oxygenation/ventilation is now inadequate.","difficulty":"Easy"},{"id":"c05_q02","question":"Which finding is classic for upper airway obstruction?","options":["A. Wheezing","B. Stridor","C. Crackles","D. Irregular rate with no abnormal sound"],"correct":1,"rationale":"Upper airway obstruction (e.g., croup, foreign body, epiglottitis) classically produces stridor.","difficulty":"Easy"},{"id":"c05_q03","question":"Which finding is classic for lower airway disease?","options":["A. Stridor","B. Wheezing with prolonged expiration","C. Grunting","D. Lethargy alone"],"correct":1,"rationale":"Lower airway disease (e.g., asthma, bronchiolitis) classically produces wheezing with prolonged expiration.","difficulty":"Easy"},{"id":"c05_q04","question":"Which findings are classic for lung tissue (parenchymal) disease?","options":["A. Stridor and barking cough","B. Wheezing only","C. Grunting, crackles, and diminished breath sounds","D. No abnormal sounds at all"],"correct":2,"rationale":"Parenchymal disease (e.g., pneumonia, pulmonary edema) classically produces grunting, crackles, and diminished breath sounds.","difficulty":"Medium"},{"id":"c05_q05","question":"What characterizes disordered control of breathing?","options":["A. Stridor with barking cough","B. Wheezing with prolonged expiration","C. An irregular rate/pattern without the classic sounds of the other three categories","D. Grunting and crackles"],"correct":2,"rationale":"Disordered control of breathing (from a CNS problem, toxin, or neuromuscular disease) causes an irregular rate/pattern without the classic sounds seen in the other three categories.","difficulty":"Medium"},{"id":"c05_q06","question":"A child who was struggling hard to breathe now appears to have less work of breathing. What should this prompt?","options":["A. Immediate reassurance that the child is improving","B. Suspicion of exhaustion/impending failure rather than automatic reassurance","C. Discharge from EMS care","D. No further assessment is needed"],"correct":1,"rationale":"Decreasing work of breathing in a previously struggling child can reflect exhaustion rather than improvement — a dangerous, easily misread sign requiring close reassessment.","difficulty":"Hard"},{"id":"c05_q07","question":"Which PAT change suggests impending respiratory failure?","options":["A. Appearance shifting from anxious/agitated to lethargic","B. Appearance shifting from lethargic to anxious","C. Improved skin color","D. No PAT change is relevant"],"correct":0,"rationale":"A shift in Appearance from anxious/agitated to lethargic on repeat PAT is a warning sign of impending respiratory failure.","difficulty":"Medium"},{"id":"c05_q08","question":"Should a provider wait for SpO2 to drop before escalating respiratory support?","options":["A. Yes, SpO2 is the only reliable indicator","B. No — other findings often precede a measurable SpO2 drop and should prompt earlier escalation","C. Only in infants","D. Only during interfacility transport"],"correct":1,"rationale":"Grunting, decreasing WOB after struggling, and PAT Appearance changes often precede a measurable drop in SpO2 and should prompt escalation before saturation falls.","difficulty":"Medium"},{"id":"c05_q09","question":"What is appropriate field management for respiratory distress (not failure)?","options":["A. Immediate bag-mask ventilation for all patients","B. Positioning of comfort, supplemental oxygen, and category-targeted treatment with close monitoring","C. No treatment until arrival at the hospital","D. Immediate advanced airway placement"],"correct":1,"rationale":"Distress is managed with positioning of comfort, oxygen, and treatment targeted to the likely category, with close monitoring for transition to failure.","difficulty":"Easy"},{"id":"c05_q10","question":"What is appropriate field management for respiratory failure?","options":["A. Positioning of comfort and observation only","B. Assisted ventilation (BVM with high-flow oxygen) and rapid transport","C. Withholding oxygen until intubation","D. Discharge at scene"],"correct":1,"rationale":"Respiratory failure requires assisted ventilation with high-flow oxygen and rapid transport; PEPP frames deeper airway/arrest management as PALS-reviewer content.","difficulty":"Easy"},{"id":"c05_q11","question":"Where does PEPP direct providers for drug-assisted airway management and arrest-specific ventilation parameters?","options":["A. The BLS reviewer","B. The PALS reviewer","C. This is fully covered in PEPP itself","D. No resource is referenced"],"correct":1,"rationale":"PEPP frames respiratory failure management as field recognition and initial stabilization, deferring drug-assisted airway management and arrest-specific ventilation depth to the PALS reviewer.","difficulty":"Medium"},{"id":"c05_q12","question":"Why are respiratory problems especially significant in pediatric prehospital care?","options":["A. They are the leading pathway to pediatric cardiac arrest","B. They never progress to failure in children","C. They are less common in children than adults","D. They have no relationship to cardiac arrest in children"],"correct":0,"rationale":"Unlike adults, where a primary cardiac event is more common, respiratory problems are the leading pathway to pediatric cardiac arrest, making early recognition high-yield.","difficulty":"Medium"},{"id":"c05_q13","question":"Why is categorizing a respiratory problem by mechanism (upper airway, lower airway, tissue, control) clinically useful?","options":["A. It has no treatment implications","B. It guides both expected exam findings and which field treatment is appropriate","C. It only matters for documentation","D. It replaces the need for a primary assessment"],"correct":1,"rationale":"Categorizing by mechanism helps providers anticipate exam findings and select the appropriate targeted treatment (e.g., bronchodilator for lower airway disease).","difficulty":"Medium"},{"id":"c05_q14","question":"A toddler has stridor and a barking cough. Which category of respiratory compromise is most likely?","options":["A. Lower airway disease","B. Upper airway obstruction","C. Lung tissue disease","D. Disordered control of breathing"],"correct":1,"rationale":"Stridor with a barking cough is classic for upper airway obstruction, such as croup.","difficulty":"Easy"},{"id":"c05_q15","question":"An infant has an irregular breathing pattern with no wheeze, stridor, grunting, or crackles, following a suspected toxic ingestion. Which category fits best?","options":["A. Upper airway obstruction","B. Lower airway disease","C. Lung tissue disease","D. Disordered control of breathing"],"correct":3,"rationale":"An irregular rate/pattern without classic sounds, especially with a toxin as the suspected cause, fits disordered control of breathing.","difficulty":"Hard"}]},"c06":{"chapter":"c06","questions":[{"id":"c06_q01","question":"How is shock best defined?","options":["A. Systolic blood pressure below a fixed threshold","B. Inadequate delivery of oxygen and nutrients to meet tissue demands","C. Any heart rate above normal for age","D. A specific respiratory rate cutoff"],"correct":1,"rationale":"Shock is a clinical diagnosis based on inadequate tissue perfusion, not a specific blood pressure value.","difficulty":"Easy"},{"id":"c06_q02","question":"Why can a child be in shock despite a normal blood pressure?","options":["A. Children cannot develop shock","B. Children compensate well via tachycardia and vasoconstriction, keeping BP normal until late","C. Blood pressure is not a useful vital sign in children","D. Normal BP always excludes shock"],"correct":1,"rationale":"Pediatric compensatory mechanisms (tachycardia, vasoconstriction) maintain blood pressure well into shock — this is compensated shock.","difficulty":"Medium"},{"id":"c06_q03","question":"What does hypotension indicate in a child with suspected shock?","options":["A. An early warning sign that appears well before other findings","B. Decompensated shock — a late, ominous sign","C. That the child is not in shock","D. A benign finding requiring no action"],"correct":1,"rationale":"Hypotension in pediatric shock is a late finding, indicating exhausted compensatory mechanisms — decompensated shock.","difficulty":"Medium"},{"id":"c06_q04","question":"Which finding is part of recognizing compensated shock?","options":["A. Delayed capillary refill with normal BP","B. Hypotension with bradycardia","C. Normal capillary refill and normal heart rate","D. Hypertension"],"correct":0,"rationale":"Compensated shock presents with perfusion abnormalities like delayed capillary refill while blood pressure remains normal for age.","difficulty":"Easy"},{"id":"c06_q05","question":"Which shock category is most common in children overall?","options":["A. Cardiogenic","B. Hypovolemic","C. Obstructive","D. Neurogenic"],"correct":1,"rationale":"Hypovolemic shock, from fluid or blood loss, is the most common category of pediatric shock overall.","difficulty":"Easy"},{"id":"c06_q06","question":"Which of the following is a type of distributive shock?","options":["A. Hemorrhagic shock","B. Septic shock","C. Tension pneumothorax","D. Myocarditis-related shock"],"correct":1,"rationale":"Septic shock, along with anaphylactic and neurogenic shock, falls under the distributive category (abnormal vessel tone/permeability).","difficulty":"Medium"},{"id":"c06_q07","question":"What causes cardiogenic shock in children?","options":["A. Fluid loss from vomiting/diarrhea","B. Pump failure from congenital heart disease, myocarditis, or arrhythmia","C. Allergen exposure","D. Tension pneumothorax"],"correct":1,"rationale":"Cardiogenic shock results from the heart's failure to pump effectively, due to causes like congenital heart disease, myocarditis, or arrhythmia.","difficulty":"Medium"},{"id":"c06_q08","question":"Which shock category is caused by a physical obstruction to blood flow?","options":["A. Hypovolemic","B. Distributive","C. Obstructive","D. Cardiogenic"],"correct":2,"rationale":"Obstructive shock results from a physical blockage to blood flow, such as tension pneumothorax, cardiac tamponade, or massive pulmonary embolism.","difficulty":"Medium"},{"id":"c06_q09","question":"A febrile child has warm, flushed skin, bounding pulses, and altered mental status. What should this suggest?","options":["A. This cannot be shock since the skin is warm","B. Early septic (distributive) shock, which can present differently from cold, mottled hypovolemic shock","C. Definite hypovolemic shock","D. Normal findings requiring no action"],"correct":1,"rationale":"Early septic shock can present with warm, flushed skin and bounding pulses rather than the cold, mottled presentation typical of hypovolemic shock, despite poor perfusion.","difficulty":"Hard"},{"id":"c06_q10","question":"What PAT findings are most suggestive of shock?","options":["A. Abnormal work of breathing only","B. Abnormal Appearance and/or abnormal Circulation to Skin, often with normal-appearing work of breathing","C. Stridor and wheeze","D. Normal Appearance and normal Circulation to Skin"],"correct":1,"rationale":"Shock often first appears on the PAT as an Appearance abnormality and/or abnormal Circulation to Skin, frequently with normal-appearing work of breathing (distinguishing it from a primary respiratory problem).","difficulty":"Medium"},{"id":"c06_q11","question":"What is the priority field treatment for suspected anaphylactic shock?","options":["A. Isotonic fluid bolus only","B. Epinephrine","C. Needle decompression","D. Oral antihistamine only"],"correct":1,"rationale":"Epinephrine is the priority treatment for anaphylactic shock; fluids and other supportive measures are adjuncts.","difficulty":"Easy"},{"id":"c06_q12","question":"A trauma patient has unilateral absent breath sounds, tracheal deviation, and signs of shock. What is the suspected category and priority intervention?","options":["A. Hypovolemic shock — fluid bolus","B. Obstructive shock from tension pneumothorax — needle decompression per protocol","C. Cardiogenic shock — cautious fluids","D. Anaphylactic shock — epinephrine"],"correct":1,"rationale":"Unilateral absent breath sounds and tracheal deviation in a trauma patient with shock suggest tension pneumothorax (obstructive shock), requiring needle decompression per protocol.","difficulty":"Hard"},{"id":"c06_q13","question":"What is the general supportive field management for a child in shock, regardless of category?","options":["A. Withhold oxygen until cause is confirmed","B. Supplemental oxygen, positioning, keep warm, and rapid transport","C. Cooling measures and fluid restriction","D. No supportive care is needed before hospital arrival"],"correct":1,"rationale":"General shock management includes supplemental oxygen, positioning (supine, legs elevated if tolerated), keeping the child warm, and rapid transport.","difficulty":"Easy"},{"id":"c06_q14","question":"Where does PEPP direct providers for drug dosing and advanced shock/arrest resuscitation algorithms?","options":["A. The BLS reviewer","B. The PALS reviewer","C. This chapter covers it fully","D. No resource is referenced"],"correct":1,"rationale":"PEPP covers field recognition and initial stabilization of shock, deferring drug dosing tables and advanced resuscitation algorithms to the PALS reviewer.","difficulty":"Medium"},{"id":"c06_q15","question":"Why does PEPP emphasize perfusion signs over blood pressure for recognizing shock?","options":["A. Blood pressure cuffs are unreliable in children","B. Perfusion signs (capillary refill, skin findings, pulse quality, mental status) change earlier than blood pressure in pediatric shock","C. Blood pressure is more important than perfusion signs","D. Perfusion signs are only relevant in adults"],"correct":1,"rationale":"Because children compensate so effectively, perfusion signs deteriorate well before blood pressure falls, making them the earlier and more reliable indicators of shock.","difficulty":"Hard"}]},"c07":{"chapter":"c07","questions":[{"id":"c07_q01","question":"How common are primary cardiac events as a cause of pediatric emergencies compared to adults?","options":["A. Equally common","B. More common in children","C. Rare in children compared to adults","D. Primary cardiac events never occur in children"],"correct":2,"rationale":"Unlike adults, where primary cardiac events are a common cause of collapse, primary cardiac disease is a rare cause of pediatric emergencies; most pediatric cardiac problems are secondary.","difficulty":"Easy"},{"id":"c07_q02","question":"What is the most common cause of pediatric bradycardia?","options":["A. Primary conduction system disease","B. Hypoxia","C. Electrolyte imbalance","D. Medication overdose"],"correct":1,"rationale":"Hypoxia is the most common cause of pediatric bradycardia encountered in the field.","difficulty":"Easy"},{"id":"c07_q03","question":"What is the correct field priority for a symptomatic bradycardic infant?","options":["A. Treat the rhythm number directly without addressing breathing","B. Oxygenate and ventilate first, addressing the underlying cause","C. Wait for a 12-lead ECG before any intervention","D. Apply ice to the chest"],"correct":1,"rationale":"Because pediatric bradycardia is usually caused by hypoxia, the priority is oxygenation and ventilation to treat the underlying cause, not treating the rhythm number alone.","difficulty":"Medium"},{"id":"c07_q04","question":"Besides hypoxia, what other factors can cause pediatric bradycardia?","options":["A. Increased vagal tone, hypothermia, increased ICP","B. Dehydration alone","C. Fever alone","D. Anxiety alone"],"correct":0,"rationale":"Increased vagal tone, hypothermia, and increased intracranial pressure are other recognized causes of pediatric bradycardia, in addition to hypoxia.","difficulty":"Medium"},{"id":"c07_q05","question":"How does sinus tachycardia typically present?","options":["A. A fixed, very rapid rate with no clear trigger","B. A variable rate with a clear trigger (fever, pain, anxiety, dehydration, shock) that resolves as the cause is treated","C. Always slower than 150 bpm","D. Only seen in adolescents"],"correct":1,"rationale":"Sinus tachycardia is a compensatory response with a variable rate tied to an identifiable trigger, resolving as that trigger is treated.","difficulty":"Easy"},{"id":"c07_q06","question":"How does SVT typically present, in contrast to sinus tachycardia?","options":["A. A fixed, very rapid rate that does not vary with stimulation","B. A slow, variable rate","C. Identical to sinus tachycardia in every way","D. Only occurs during exercise"],"correct":0,"rationale":"SVT is a primary rhythm disturbance with a fixed, very rapid rate that does not vary with stimulation, distinguishing it from sinus tachycardia.","difficulty":"Medium"},{"id":"c07_q07","question":"An infant has a heart rate fixed at 240 bpm that does not change with stimulation and no clear triggering illness. What should this suggest?","options":["A. Sinus tachycardia from fever","B. Supraventricular tachycardia (SVT)","C. Normal infant heart rate","D. Bradycardia"],"correct":1,"rationale":"A fixed, very rapid rate (often >220 bpm in infants) that does not vary with stimulation and lacks a clear trigger is characteristic of SVT.","difficulty":"Hard"},{"id":"c07_q08","question":"Why should a provider ask about a child's known congenital heart disease?","options":["A. It is not clinically relevant in the field","B. The child may have a baseline vital signs/SpO2 that differs from typical norms, and is at elevated risk for arrhythmia, heart failure, and cardiogenic shock","C. It only matters for billing purposes","D. Congenital heart disease patients never develop arrhythmias"],"correct":1,"rationale":"Children with congenital heart disease may have different baseline vitals/oxygen saturations and are at higher risk for arrhythmia, heart failure, and cardiogenic shock.","difficulty":"Medium"},{"id":"c07_q09","question":"What family history finding raises suspicion for a cardiac channelopathy in a child with unexplained collapse?","options":["A. Family history of diabetes","B. Family history of sudden unexplained death in a young relative","C. Family history of asthma","D. Family history of migraine"],"correct":1,"rationale":"Sudden unexplained death in a young relative is a recognized clue suggesting an underlying cardiac channelopathy risk.","difficulty":"Medium"},{"id":"c07_q10","question":"What are the field priorities for a suspected pediatric cardiac emergency?","options":["A. Recognition, identifying reversible causes (especially hypoxia), and rapid transport with reassessment","B. Immediate antiarrhythmic drug administration without assessment","C. Delaying transport until a definitive diagnosis is made","D. Ignoring the rhythm and focusing only on blood pressure"],"correct":0,"rationale":"Field priorities are recognition via PAT/primary assessment, identifying reversible causes like hypoxia, and rapid transport with ongoing reassessment.","difficulty":"Medium"},{"id":"c07_q11","question":"Where should a provider look for arrest algorithms, defibrillation/cardioversion dosing, and antiarrhythmic drug dosing?","options":["A. This PEPP chapter covers it fully","B. The PALS reviewer","C. The BLS reviewer","D. No resource covers this"],"correct":1,"rationale":"This chapter deliberately does not reproduce arrest algorithms or drug dosing; the PALS reviewer covers this in full depth.","difficulty":"Easy"},{"id":"c07_q12","question":"A bradycardic infant has poor perfusion and diminished respiratory effort. What should the provider suspect first?","options":["A. A primary cardiac conduction disorder requiring immediate cardioversion","B. A respiratory or hypoxia problem, treatable by supporting oxygenation/ventilation","C. Nothing is wrong since bradycardia is normal in infants","D. A toxic ingestion is the only possible cause"],"correct":1,"rationale":"A bradycardic, poorly perfusing infant is usually a respiratory or hypoxia problem until proven otherwise, so oxygenation/ventilation is the priority.","difficulty":"Medium"},{"id":"c07_q13","question":"Why does PEPP limit its cardiac chapter to recognition rather than full resuscitation depth?","options":["A. To avoid duplicating PALS's authoritative arrest-algorithm and drug-dosing content","B. Because cardiac emergencies are not important in pediatrics","C. Because PALS does not cover cardiac arrest","D. Because field providers never encounter cardiac emergencies"],"correct":0,"rationale":"PEPP's guardrail is to avoid duplicating PALS's resuscitation content, focusing instead on field recognition and initial stabilization, with PALS as the authoritative depth resource.","difficulty":"Medium"},{"id":"c07_q14","question":"A school-age child with known repaired congenital heart disease has a caregiver report of a resting SpO2 of 88% at baseline. What does this mean for field assessment?","options":["A. 88% must always be treated as an emergency abnormal finding","B. This may be the child's normal baseline, so it should be compared to their known baseline rather than typical pediatric norms","C. This value should be ignored entirely","D. It indicates the caregiver is providing inaccurate information"],"correct":1,"rationale":"Children with congenital heart disease may have a baseline SpO2 different from typical norms; providers should ask about and compare to the child's known personal baseline.","difficulty":"Hard"}]},"c08":{"chapter":"c08","questions":[{"id":"c08_q01","question":"What does AVPU stand for?","options":["A. Alert, Voice, Pain, Unresponsive","B. Airway, Vitals, Pulse, Unconsciousness","C. Appearance, Ventilation, Perfusion, Urgency","D. Alert, Vital, Perfused, Unstable"],"correct":0,"rationale":"AVPU is a simple scale for level of consciousness: Alert, responds to Voice, responds to Pain, or Unresponsive.","difficulty":"Easy"},{"id":"c08_q02","question":"Which PAT leg often provides the earliest clue to altered mental status?","options":["A. Work of Breathing","B. Circulation to Skin","C. Appearance","D. None of the PAT legs relate to mental status"],"correct":2,"rationale":"Appearance findings (eye contact, interactiveness, cry quality) often reveal altered mental status before a formal AVPU assessment.","difficulty":"Easy"},{"id":"c08_q03","question":"What does the AEIOU-TIPS mnemonic help a provider recall?","options":["A. Steps of the primary assessment","B. Reversible causes of altered mental status","C. PAT legs","D. Categories of respiratory compromise"],"correct":1,"rationale":"AEIOU-TIPS recalls reversible causes of altered mental status: Alcohol, Epilepsy, Infection, Overdose, Uremia/metabolic, Trauma/temperature, Insulin/hypoglycemia, Psychiatric, Shock/stroke.","difficulty":"Medium"},{"id":"c08_q04","question":"Why is a glucose check emphasized for every altered pediatric patient when a meter is available?","options":["A. Hypoglycemia is rare and unimportant in children","B. Hypoglycemia is common and rapidly reversible","C. Glucose checks are only relevant for diabetic patients","D. It is required for billing, not clinical reasons"],"correct":1,"rationale":"Hypoglycemia is a common, easily and rapidly reversible cause of pediatric altered mental status, making a glucose check a high-value, low-cost intervention.","difficulty":"Easy"},{"id":"c08_q05","question":"What are the field priorities during an active pediatric seizure?","options":["A. Place an object in the mouth to prevent tongue biting","B. Protect the airway and from injury, check glucose, time the seizure","C. Restrain the child's limbs firmly","D. Administer oral medication during the seizure"],"correct":1,"rationale":"Correct field management is protecting the airway/positioning, protecting from injury, checking glucose, and timing the seizure — never placing objects in the mouth.","difficulty":"Easy"},{"id":"c08_q06","question":"What defines status epilepticus?","options":["A. Any seizure lasting more than 1 minute","B. A seizure lasting more than 5 minutes, or repeated seizures without return to baseline","C. Only seizures with fever","D. Only seizures in infants under 6 months"],"correct":1,"rationale":"Status epilepticus is defined as a seizure lasting more than 5 minutes, or repeated seizures without the patient returning to baseline between them.","difficulty":"Medium"},{"id":"c08_q07","question":"Where is benzodiazepine dosing for status epilepticus detailed?","options":["A. This PEPP chapter","B. The PALS reviewer","C. The BLS reviewer","D. No resource covers it"],"correct":1,"rationale":"Consistent with PEPP's guardrail against duplicating PALS content, drug dosing for status epilepticus is detailed in the PALS reviewer.","difficulty":"Medium"},{"id":"c08_q08","question":"What is the typical age range for febrile seizures?","options":["A. 6 months to 5 years","B. Birth to 1 month","C. 10 to 18 years","D. Only over age 10"],"correct":0,"rationale":"Febrile seizures are most typical in children 6 months to 5 years, associated with a rapidly rising fever.","difficulty":"Easy"},{"id":"c08_q09","question":"Which description fits a simple febrile seizure?","options":["A. Focal, lasting 20 minutes, recurs within hours","B. Generalized, lasting less than 15 minutes, no recurrence in 24 hours, returns to baseline","C. Any seizure with a fever regardless of duration","D. A seizure that does not return to baseline afterward"],"correct":1,"rationale":"A simple febrile seizure is generalized, brief (under 15 minutes), non-recurrent within 24 hours, with return to baseline mental status afterward.","difficulty":"Medium"},{"id":"c08_q10","question":"A febrile child has a focal seizure lasting 20 minutes. How should this be classified?","options":["A. A simple febrile seizure requiring no special concern","B. A complex febrile seizure, warranting a higher level of concern","C. Not a seizure at all","D. Status epilepticus by definition regardless of duration criteria"],"correct":1,"rationale":"Focal features and duration over 15 minutes meet the definition of a complex febrile seizure, which warrants greater concern than a simple febrile seizure (though it may also cross into status epilepticus if it continues beyond 5 minutes without stopping).","difficulty":"Hard"},{"id":"c08_q11","question":"What signs suggest increased intracranial pressure in an infant?","options":["A. Sunken fontanelle and tachypnea","B. Bulging fontanelle, decreasing consciousness, irregular respiratory pattern","C. Normal fontanelle and improved alertness","D. Warm, flushed skin"],"correct":1,"rationale":"A bulging fontanelle, decreasing level of consciousness, and an irregular respiratory pattern suggest increased intracranial pressure in an infant.","difficulty":"Medium"},{"id":"c08_q12","question":"What is the Cushing triad?","options":["A. Hypotension, tachycardia, tachypnea","B. Hypertension, bradycardia, irregular respirations","C. Fever, rash, vomiting","D. Tachycardia, hypertension, diaphoresis"],"correct":1,"rationale":"The Cushing triad — hypertension, bradycardia, and irregular respirations — is a late and ominous sign of increased intracranial pressure.","difficulty":"Medium"},{"id":"c08_q13","question":"Why should hypoxia and hypotension be avoided in a child with suspected increased intracranial pressure?","options":["A. They have no effect on brain injury","B. Both worsen secondary brain injury","C. They only affect cardiac function, not the brain","D. They are unavoidable and not a treatment priority"],"correct":1,"rationale":"Both hypoxia and hypotension worsen secondary brain injury in a child with elevated intracranial pressure, making their avoidance a key field priority.","difficulty":"Medium"},{"id":"c08_q14","question":"Why does a trend of decreasing responsiveness across serial reassessments matter more than a single mental status snapshot?","options":["A. It doesn't — only the first assessment matters","B. A worsening trend indicates ongoing deterioration that a single value could miss","C. Trends are only relevant in adults","D. Serial reassessment is not recommended in pediatric care"],"correct":1,"rationale":"A single mental status value can miss an evolving problem; a trend toward decreasing responsiveness reveals ongoing deterioration and should prompt escalation.","difficulty":"Hard"}]}},"scenarios":{"c01":{"chapter":"c01","cases":[{"id":"c01_s01","title":"The 'Reassuring' Blood Pressure","presentation":"A 6-year-old boy fell from a bicycle and has an obviously deformed thigh with visible bruising. He is pale and anxious. His blood pressure reads within the normal range for his age, but his heart rate is elevated.","vitals":{"hr":"128 bpm (elevated for age)","bp":"94/62 mmHg (age-normal)","rr":"26 bpm","skin":"Pale, cool"},"question":"How should the 'normal' blood pressure be interpreted?","options":["A: It rules out significant blood loss or shock.","B: It should NOT be reassuring — children compensate well and maintain blood pressure until a large percentage of volume is lost; the tachycardia and pale, cool skin suggest early compensated shock.","C: It means his heart rate reading is inaccurate.","D: It indicates he is anxious only, with no physiologic concern."],"correct":1,"explanation":"Blood pressure is a late sign in pediatric shock. This child's tachycardia and pale, cool skin — despite a numerically normal blood pressure for his age — suggest early compensated shock from his femur fracture, and should prompt close monitoring and volume assessment rather than reassurance from the BP alone.","clinicalPearl":"In children, don't let a 'normal' blood pressure talk you out of what the rest of the exam is telling you."},{"id":"c01_s02","title":"The Screaming Toddler","presentation":"A 2-year-old girl with a fever is screaming and clinging to her mother, arching away whenever you approach with your stethoscope.","vitals":{"temp":"102.6 F","hr":"Elevated, difficult to auscultate due to crying","loc":"Alert, distressed"},"question":"What is the best approach to complete a useful assessment?","options":["A: Separate her from her mother to get a controlled exam.","B: Keep her on her mother's lap, demonstrate the stethoscope on the mother first, and assess from a distance (appearance, work of breathing, color) before hands-on exam.","C: Restrain her firmly to listen to her lungs.","D: Skip the exam since she won't cooperate."],"correct":1,"explanation":"Toddlers fear separation and unfamiliar equipment. Keeping her with her caregiver, demonstrating tools first, and starting with an across-the-room observational assessment (matching the developmental-stage approach in this chapter) both calms the child and yields more reliable findings than forcing a hands-on exam immediately.","clinicalPearl":"With toddlers, the best exam often starts before you ever touch them — watch first, demonstrate second, touch last."},{"id":"c01_s03","title":"Small Loss, Big Percentage","presentation":"A 9 kg infant has been vomiting and having diarrhea for 18 hours. The caregiver estimates about 300 mL of combined fluid loss, which they describe as 'not that much.'","vitals":{"weight":"9 kg","estimated loss":"~300 mL","hr":"elevated","skin":"dry mucous membranes, decreased tears"},"question":"Why is this fluid loss more significant than the caregiver's framing suggests?","options":["A: 300 mL is trivial regardless of the infant's size.","B: A child's absolute circulating blood/fluid volume is small, so 300 mL represents a much larger percentage of this infant's total volume than the same amount would in an adult.","C: Fluid loss is never clinically significant in infants.","D: This amount is only concerning if the infant is over 1 year old."],"correct":1,"explanation":"Because total circulating volume scales with body size, an absolute loss that sounds modest can represent a dangerously large percentage of a small infant's total volume — one of the core anatomic/physiologic reasons children are not small adults when estimating losses.","clinicalPearl":"Always translate an absolute fluid loss into a percentage of THIS child's estimated total volume — the same number means very different things at different weights."}]},"c02":{"chapter":"c02","cases":[{"id":"c02_s01","title":"From the Doorway","presentation":"You enter a home and see a 3-year-old boy sitting quietly in his mother's lap. He is looking around the room, tracking your movement, and reaches for a toy his sister offers. His breathing looks effortless and his skin has a normal pink color.","vitals":{"appearance":"Alert, interactive, tracks movement","wob":"No retractions, no abnormal sounds","circulation":"Normal color"},"question":"What does this PAT pattern suggest, and what should you do next?","options":["A: All three legs normal — this is a reassuring PAT; proceed to a full hands-on primary assessment at a normal pace.","B: This is enough information to clear the child without further assessment.","C: You should immediately begin aggressive interventions given the visit itself is concerning.","D: Skip vital signs since the child looks fine."],"correct":0,"explanation":"All three PAT legs (Appearance, Work of Breathing, Circulation to Skin) appear normal, giving a reassuring general impression. This sets a calmer pace for the encounter, but a full hands-on primary assessment (ABCDE) still follows — the PAT never substitutes for it.","clinicalPearl":"A reassuring PAT buys you time and calm, not an exemption from the primary assessment."},{"id":"c02_s02","title":"Two Legs Down","presentation":"A 5-year-old girl with a history of asthma is sitting in the tripod position, with visible subcostal and intercostal retractions and audible wheezing. She is alert, tracking you, and answering questions appropriately. Her skin color looks normal.","vitals":{"appearance":"Alert, interactive (normal)","wob":"Tripod position, retractions, wheeze (abnormal)","circulation":"Normal color"},"question":"Which PAT category does this pattern suggest, and how urgent is it?","options":["A: CNS/metabolic problem — treat as a neurologic emergency.","B: Respiratory problem (abnormal Work of Breathing with normal Appearance and Circulation) — urgent but with intact compensation reflected by her normal Appearance.","C: Cardiopulmonary failure — the most urgent category.","D: A normal, reassuring PAT."],"correct":1,"explanation":"Only the Work of Breathing leg is abnormal here; her Appearance remaining normal suggests she is still compensating well despite significant respiratory effort. This points to a respiratory category requiring urgent treatment (e.g., bronchodilator therapy) rather than the higher-urgency multi-leg patterns.","clinicalPearl":"A normal Appearance despite visible respiratory effort is a relatively reassuring sign — it means the compensation is still working."},{"id":"c02_s03","title":"All Three Legs Abnormal","presentation":"A 7-month-old infant is limp and unresponsive to his mother's voice, with slow, irregular, gasping-appearing breaths and dusky, mottled skin.","vitals":{"appearance":"Limp, unresponsive (abnormal)","wob":"Irregular, gasping breaths (abnormal)","circulation":"Dusky, mottled (abnormal)"},"question":"What does this pattern indicate, and what is the priority?","options":["A: A mild, self-limited illness requiring routine transport.","B: Cardiopulmonary failure — abnormal findings across all three PAT legs — the highest-acuity pattern, requiring the most immediate, aggressive response.","C: A purely circulatory problem with no respiratory component.","D: This pattern is not clinically meaningful without vital signs first."],"correct":1,"explanation":"Abnormal findings across all three PAT legs (Appearance, Work of Breathing, Circulation to Skin) together indicate cardiopulmonary failure, the most severe PAT pattern, demanding the most urgent, simultaneous life-saving response — this recognition happens before any vital sign is even obtained.","clinicalPearl":"All three legs abnormal is the PAT's loudest alarm — it means go now, with everything, before you've measured a single vital sign."}]},"c03":{"chapter":"c03","cases":[{"id":"c03_s01","title":"Fix It As You Find It","presentation":"A 4-year-old is struck by a car at low speed. Your PAT shows abnormal Appearance and Work of Breathing. On primary assessment, you find her airway is partially obstructed by blood and secretions from a facial injury.","vitals":{"appearance":"Lethargic (abnormal)","wob":"Gurgling respirations (abnormal)","airway":"Partially obstructed"},"question":"What should you do upon finding the airway obstruction during the 'A' step?","options":["A: Note the finding and continue to assess breathing, circulation, disability, and exposure first.","B: Clear the airway immediately before continuing to the next steps of the primary assessment.","C: Wait until the secondary assessment to address the airway.","D: Only address it if her oxygen saturation is also abnormal."],"correct":1,"explanation":"Life threats found during the primary assessment are treated the moment they are identified — an obstructed airway found at 'A' is cleared immediately before proceeding to 'B' and beyond, rather than completing the checklist first.","clinicalPearl":"ABCDE is not a form to fill out top to bottom — it's an ordered scan that stops for treatment the instant it finds a problem."},{"id":"c03_s02","title":"Setting the Pace","presentation":"You respond to two children after a household chemical exposure. The PAT on the first child shows all three legs normal; the PAT on the second child shows abnormal Appearance, Work of Breathing, and Circulation to Skin together.","vitals":{"child1_PAT":"All three legs normal","child2_PAT":"All three legs abnormal (cardiopulmonary failure pattern)"},"question":"How should the primary assessment differ between these two children?","options":["A: Identically — the PAT has no bearing on how the primary assessment proceeds.","B: The second child's primary assessment should proceed immediately and rapidly, potentially with simultaneous interventions, while the first child's primary assessment can proceed at a calmer, still-thorough pace.","C: Only the first child needs a primary assessment.","D: Only the second child needs a primary assessment."],"correct":1,"explanation":"The PAT sets the urgency and pace for the primary assessment that follows. The child with the cardiopulmonary-failure PAT pattern needs an immediate, rapid, simultaneous-intervention approach, while the child with a reassuring PAT can be assessed thoroughly but at a normal pace — both still receive a full ABCDE exam.","clinicalPearl":"The PAT is your triage dial for the primary assessment's speed — it never decides whether the exam happens, only how fast."},{"id":"c03_s03","title":"The Priority Decision","presentation":"After completing ABCDE on an 8-year-old with a minor laceration and stable vital signs across the board, you must decide how to proceed.","vitals":{"airway":"Patent","breathing":"Normal rate/effort","circulation":"Normal perfusion, controlled minor bleeding","disability":"Alert, normal","exposure":"Minor laceration only"},"question":"What is the correct next step based on this primary assessment?","options":["A: Assign a high-priority designation and initiate rapid transport with ALS intercept.","B: Assign a low-priority designation, allowing a more complete secondary assessment (history, focused exam) on scene.","C: Skip the secondary assessment entirely since ABCDE is complete.","D: Repeat the PAT indefinitely instead of proceeding."],"correct":1,"explanation":"Stable findings across the ABCDE primary assessment support a low-priority designation, which allows time for a more complete secondary assessment (history-taking, focused exam) to be performed on scene rather than rushing to transport.","clinicalPearl":"The primary assessment's real output is a priority label — 'high' means move fast and treat en route; 'low' means you can afford the thorough secondary assessment on scene."}]},"c04":{"chapter":"c04","cases":[{"id":"c04_s01","title":"Asking the Teenager Directly","presentation":"A 15-year-old girl comes to the ambulance with her mother after a syncopal episode at school. The mother immediately begins answering all your questions about symptoms and events before the patient can speak.","vitals":{"hr":"88 bpm","bp":"108/68 mmHg","loc":"Alert, oriented"},"question":"What is the best approach to history-taking here?","options":["A: Rely entirely on the mother's account since she is the legal guardian.","B: Direct questions to the teenager herself, using the mother's account to supplement rather than replace her report — and consider some private conversation time.","C: Ignore the mother's input entirely.","D: Skip history-taking since vitals are stable."],"correct":1,"explanation":"Adolescents should be asked directly about their symptoms whenever possible; the caregiver's account supplements rather than replaces the patient's own report. Given adolescents' preference for privacy, some interview time apart from the caregiver may also yield more complete and honest information (e.g., about substance use, stress, or other sensitive factors relevant to a syncopal episode).","clinicalPearl":"A teenager who can speak for herself should be given the chance to — caregivers supplement the history, they don't own it."},{"id":"c04_s02","title":"Keeping Mom in the Room","presentation":"A 3-year-old boy needs an IV start for dehydration. A new EMT suggests asking the mother to step out 'so she doesn't get upset.' The mother is calm and has been comforting the child effectively throughout the encounter.","vitals":{"child":"Anxious but calming with mother present","mother":"Calm, cooperative"},"question":"What does family-centered care recommend here?","options":["A: Ask the mother to leave to avoid her becoming upset.","B: Keep the calm, cooperative mother present during the procedure — family-centered care treats her as a partner, and her presence is likely to reduce the child's distress without slowing the procedure.","C: Only allow the father to be present, not the mother.","D: Perform the procedure in a separate room without any caregiver present."],"correct":1,"explanation":"Family-centered care supports keeping a calm, cooperative caregiver present during most procedures, including IV starts — this typically reduces the child's distress and improves cooperation without meaningfully slowing the procedure. Removing a helpful caregiver by default (rather than for a specific clinical reason) works against this principle.","clinicalPearl":"A calm caregiver is usually your best assistant during a procedure, not an obstacle to remove."},{"id":"c04_s03","title":"Interpreting for the Family","presentation":"A family speaking only Spanish brings in their feverish 6-year-old. Their 10-year-old sibling, who speaks some English, offers to translate for the parents.","vitals":{"patient":"6-year-old, febrile","family":"Spanish-speaking only","sibling":"10-year-old, offers to translate"},"question":"What is the correct approach to communication in this scenario?","options":["A: Use the 10-year-old sibling as the interpreter since they volunteered.","B: Use a professional interpretation service rather than relying on a child family member to interpret medical information.","C: Proceed without any interpretation since the situation seems routine.","D: Wait for the family to learn English before continuing care."],"correct":1,"explanation":"Relying on a child — especially one who is also a family member of the patient — to interpret medical information is inappropriate and risks miscommunication and undue burden on the child. Professional interpretation services should be used to ensure accurate, appropriate communication with the family.","clinicalPearl":"A willing child interpreter is still the wrong interpreter — professional services protect both accuracy and the child from an inappropriate role."}]},"c05":{"chapter":"c05","cases":[{"id":"c05_s01","title":"The 'Calmer' Toddler","presentation":"A 2-year-old with a two-day history of cough and wheeze was working very hard to breathe 20 minutes ago (retractions, tachypnea). On reassessment, the retractions look less pronounced and the child seems 'calmer,' though still tachypneic and now slightly less interactive.","vitals":{"hr":"168 bpm","rr":"44/min","spo2":"93% room air","appearance":"Less interactive than 20 minutes ago"},"question":"How should this change be interpreted?","options":["A: The child is genuinely improving; no action is needed.","B: The apparent decrease in work of breathing combined with decreasing interactivity suggests exhaustion and impending failure, not improvement — escalate support immediately.","C: Discharge from EMS care since the child looks calmer.","D: Wait for SpO2 to fall further before acting."],"correct":1,"explanation":"A previously struggling child who appears 'calmer' but is also less interactive, still tachypneic, and hypoxic is showing signs of exhaustion, not genuine improvement. This should prompt immediate escalation of respiratory support rather than reassurance.","clinicalPearl":"'Calmer' after hard work of breathing is a red flag until proven otherwise — check mental status and oxygenation before you relax."},{"id":"c05_s02","title":"Stridor at Rest","presentation":"A 3-year-old with a barking cough develops audible stridor at rest, with mild suprasternal retractions. The child is alert, interactive, and consolable in the caregiver's lap.","vitals":{"hr":"128 bpm","rr":"32/min","spo2":"97% room air","appearance":"Alert, interactive"},"question":"What category of respiratory compromise does this represent, and what is the appropriate field approach?","options":["A: Lower airway disease — give a nebulized bronchodilator.","B: Upper airway obstruction — keep the child calm and in a position of comfort with the caregiver, minimize agitation, and monitor closely.","C: Lung tissue disease — expect crackles and diminished breath sounds.","D: Disordered control of breathing — expect an irregular respiratory pattern."],"correct":1,"explanation":"Stridor with a barking cough is classic for upper airway obstruction (e.g., croup). Since the child is still compensating well (alert, adequate oxygenation), the priority is keeping the child calm — agitation can worsen upper airway obstruction — with close monitoring rather than aggressive intervention.","clinicalPearl":"For upper airway obstruction, calm beats aggressive — crying and agitation can worsen the obstruction."},{"id":"c05_s03","title":"From Distress to Failure","presentation":"A 6-month-old with bronchiolitis has been tachypneic with nasal flaring and grunting for the past hour. On your arrival, the infant is now cyanotic around the lips, limp, and breathing irregularly with long pauses.","vitals":{"hr":"70 bpm","rr":"irregular with apneic pauses","spo2":"80% room air","appearance":"Limp, cyanotic"},"question":"What is the correct immediate field management?","options":["A: Continue observation since bronchiolitis is usually self-limited.","B: Provide assisted ventilation with bag-mask and high-flow oxygen, and initiate rapid transport.","C: Administer an oral bronchodilator and reassess in 15 minutes.","D: Withhold intervention until arrival at the hospital."],"correct":1,"explanation":"Cyanosis, limp appearance, bradycardia, and an irregular breathing pattern with apneic pauses indicate respiratory failure. This requires immediate assisted ventilation with high-flow oxygen and rapid transport; deeper arrest-specific airway management is covered by the PALS reviewer if arrest occurs.","clinicalPearl":"Bradycardia in a sick infant is a respiratory problem until proven otherwise — ventilate first."}]},"c06":{"chapter":"c06","cases":[{"id":"c06_s01","title":"Normal Blood Pressure, Abnormal Perfusion","presentation":"A 4-year-old has had three days of vomiting and diarrhea. She is irritable, has dry mucous membranes, capillary refill of 3 seconds, and cool extremities. Blood pressure is 92/60 mmHg.","vitals":{"hr":"150 bpm","bp":"92/60 mmHg","capRefill":"3 seconds","appearance":"Irritable"},"question":"How should this presentation be interpreted?","options":["A: No shock is present because the blood pressure is normal.","B: Compensated shock is present — tachycardia and delayed capillary refill indicate poor perfusion despite a normal blood pressure for age.","C: This is decompensated shock since the blood pressure is abnormal.","D: These findings are unrelated and require no action."],"correct":1,"explanation":"Tachycardia, delayed capillary refill, cool extremities, and irritability all indicate poor perfusion — compensated shock — even though the blood pressure remains normal for age. Waiting for hypotension would mean missing shock at a treatable stage.","clinicalPearl":"Normal blood pressure does not rule out shock in a child — it may just mean compensation hasn't failed yet."},{"id":"c06_s02","title":"Warm and Flushed, Not Reassuring","presentation":"A 7-year-old with a high fever is lethargic, with warm, flushed skin, bounding peripheral pulses, and a capillary refill that is brisk but the child remains difficult to arouse.","vitals":{"hr":"160 bpm","temp":"39.8°C","appearance":"Lethargic, difficult to arouse","skin":"Warm, flushed"},"question":"What should this presentation suggest?","options":["A: This cannot be shock since the skin is warm and pulses are bounding.","B: Early septic (distributive) shock, which can present with warm, flushed skin and bounding pulses rather than the cold, mottled pattern of hypovolemic shock.","C: Simple febrile illness requiring only antipyretics.","D: Cardiogenic shock from a primary cardiac problem."],"correct":1,"explanation":"Warm, flushed skin and bounding pulses can be misleadingly reassuring — combined with fever and altered mental status (lethargy), this presentation is consistent with early septic shock, a distributive shock subtype that does not always look like the classic cold, mottled hypovolemic pattern.","clinicalPearl":"Don't let warm skin fool you — early septic shock can look 'well-perfused' on the skin while the brain is already showing signs of poor perfusion."},{"id":"c06_s03","title":"Sudden Hypotension After Trauma","presentation":"A 10-year-old struck by a car has unilateral absent breath sounds on the right, tracheal deviation to the left, tachycardia, and a blood pressure that just dropped to 78/50 mmHg.","vitals":{"hr":"155 bpm","bp":"78/50 mmHg","breathSounds":"Absent on right","trachea":"Deviated left"},"question":"What is the most likely cause of shock, and what is the priority intervention?","options":["A: Hypovolemic shock from external bleeding — apply direct pressure and give fluids.","B: Obstructive shock from a tension pneumothorax — needle decompression per protocol, in addition to supportive care.","C: Anaphylactic shock — administer epinephrine.","D: This is a normal post-traumatic vital sign pattern requiring no intervention."],"correct":1,"explanation":"Unilateral absent breath sounds, tracheal deviation, and hypotension after trauma are classic for tension pneumothorax causing obstructive shock. Needle decompression per protocol is the priority intervention to relieve the obstruction, alongside oxygen and rapid transport.","clinicalPearl":"Tracheal deviation plus absent breath sounds plus shock after trauma — think tension pneumothorax and decompress, don't just give fluids."}]},"c07":{"chapter":"c07","cases":[{"id":"c07_s01","title":"The Bradycardic, Blue Infant","presentation":"A 2-month-old is found limp and dusky by a caregiver. Heart rate is 60 bpm, respiratory effort is minimal, and the infant is unresponsive to stimulation.","vitals":{"hr":"60 bpm","rr":"minimal effort","color":"Dusky/cyanotic","appearance":"Unresponsive"},"question":"What is the correct first priority?","options":["A: Immediately prepare for cardioversion.","B: Support oxygenation and ventilation first — bradycardia in this context is most likely due to hypoxia.","C: Give an antiarrhythmic medication before assessing breathing.","D: Wait for a 12-lead ECG before intervening."],"correct":1,"explanation":"A dusky, bradycardic infant with poor respiratory effort should be treated as a hypoxia-driven bradycardia — support oxygenation and ventilation immediately, since this is the most common and rapidly reversible cause. Rhythm-specific interventions are addressed in the PALS reviewer if bradycardia persists despite adequate oxygenation/ventilation.","clinicalPearl":"Bradycardia plus cyanosis plus poor effort in an infant is a breathing problem first — fix oxygenation before assuming a primary cardiac cause."},{"id":"c07_s02","title":"Sudden Rapid Heart Rate, No Trigger","presentation":"A previously well 4-month-old is fussy and poorly feeding. The monitor shows a heart rate fixed at 230 bpm that does not change with stimulation. There is no fever, and the caregiver reports no illness.","vitals":{"hr":"230 bpm, fixed","temp":"Afebrile","appearance":"Fussy, poor feeding"},"question":"What does this presentation most likely represent?","options":["A: Sinus tachycardia from an underlying fever.","B: Supraventricular tachycardia (SVT) — a fixed, very rapid rate with no clear trigger that does not vary with stimulation.","C: A normal finding in a 4-month-old.","D: Bradycardia."],"correct":1,"explanation":"A fixed, very rapid heart rate (over 220 bpm in an infant) that does not vary with stimulation, without a fever or other clear trigger, is characteristic of SVT rather than sinus tachycardia. This warrants rapid transport and notification of the receiving facility; specific rhythm management is detailed in the PALS reviewer.","clinicalPearl":"No fever, no clear cause, and a rate that won't budge with stimulation — think SVT, not sinus tachycardia."},{"id":"c07_s03","title":"Known Heart Disease, Different Baseline","presentation":"An 8-year-old with a history of repaired congenital heart disease is brought in after a minor fall, mildly anxious. Pulse oximetry reads 89%. The caregiver states this is normal for the child.","vitals":{"spo2":"89% (caregiver states this is baseline)","hr":"110 bpm","appearance":"Mildly anxious, otherwise well"},"question":"How should the SpO2 reading be interpreted?","options":["A: This must be treated as severe hypoxia requiring aggressive intervention regardless of history.","B: Compare it to the child's known personal baseline as reported by the caregiver — children with congenital heart disease may normally run lower saturations.","C: Ignore the reading since pulse oximetry is unreliable in children with heart disease.","D: Assume the caregiver is mistaken and treat as an emergency."],"correct":1,"explanation":"Children with congenital heart disease may have a baseline oxygen saturation that differs from typical norms. Providers should ask about and compare findings to the child's known baseline rather than assuming abnormality outright, while still monitoring for any acute change from that baseline.","clinicalPearl":"Always ask 'what's normal for this child?' when there's known congenital heart disease — a number that looks alarming may be their everyday baseline."}]},"c08":{"chapter":"c08","cases":[{"id":"c08_s01","title":"The Lethargic Toddler","presentation":"A 2-year-old is found unusually quiet and difficult to arouse by a caregiver. No fever is reported. A glucose meter is available on the unit.","vitals":{"avpu":"Responds to voice only","temp":"Afebrile","appearance":"Poor eye contact, decreased interactiveness"},"question":"What is the appropriate next step?","options":["A: Transport without further assessment since no fever is present.","B: Check the child's blood glucose, since hypoglycemia is a common and rapidly reversible cause of altered mental status.","C: Assume the child is simply tired and reassess in 30 minutes.","D: Withhold any intervention until arrival at the hospital."],"correct":1,"explanation":"Any altered child should have a glucose check when a meter is available, since hypoglycemia is common in children and rapidly reversible. This should be done promptly rather than assuming a benign cause without checking.","clinicalPearl":"Glucose check first, every time, when altered mental status is present and a meter is available — it's fast, easy, and can immediately explain (and treat) the problem."},{"id":"c08_s02","title":"Seizure at the Six-Minute Mark","presentation":"A 3-year-old has been having generalized tonic-clonic seizure activity for 6 minutes with no sign of stopping. The caregiver reports no fever and this has never happened before.","vitals":{"duration":"6 minutes and ongoing","temp":"Afebrile","activity":"Generalized tonic-clonic, continuous"},"question":"What does this presentation represent, and what is the priority?","options":["A: A simple febrile seizure requiring only observation.","B: Status epilepticus — a time-critical emergency requiring rapid escalation of care and transport.","C: A normal pediatric seizure pattern requiring no escalation.","D: This should be timed for another 10 minutes before taking any action."],"correct":1,"explanation":"A seizure lasting more than 5 minutes meets the definition of status epilepticus, a time-critical emergency. This is not a simple febrile seizure (there is no fever, and duration alone already exceeds the definition), and requires immediate escalation of care; benzodiazepine dosing is addressed in the PALS reviewer.","clinicalPearl":"Five minutes is the line — once a seizure crosses it, treat it as status epilepticus and escalate, don't keep waiting."},{"id":"c08_s03","title":"Bulging Fontanelle After a Fall","presentation":"A 5-month-old fell from a changing table an hour ago. The infant is increasingly difficult to arouse, has a bulging fontanelle, and now has an irregular breathing pattern.","vitals":{"fontanelle":"Bulging","rr":"Irregular pattern","appearance":"Decreasing responsiveness"},"question":"What should this presentation prompt, and what should be avoided?","options":["A: Suspicion for increased intracranial pressure — avoid hypoxia and hypotension, position to avoid jugular compression, and transport rapidly.","B: No specific concern since infants commonly have bulging fontanelles.","C: Aggressive fluid restriction and permissive hypoxia.","D: Delay transport until the fontanelle returns to normal."],"correct":0,"explanation":"A bulging fontanelle with decreasing responsiveness and an irregular respiratory pattern after a fall suggests increased intracranial pressure. Field priorities are avoiding hypoxia and hypotension (both worsen secondary brain injury), positioning to avoid jugular venous compression, and rapid transport.","clinicalPearl":"After head trauma, a bulging fontanelle plus a change in responsiveness is not incidental — treat it as rising intracranial pressure and protect the brain from secondary injury."}]}},"algorithms":{"c01":{"chapter":"c01","algorithms":[{"id":"c01_alg01","title":"Applying Anatomic/Developmental Context to Any Pediatric Encounter","description":"The foundational sequence for interpreting any pediatric finding in age- and development-appropriate context.","steps":["Identify the child's age band before interpreting any vital sign or exam finding.","Recall the anatomic differences relevant to the presenting complaint (airway: narrow/anterior/subglottic; breathing: high demand/low reserve; circulation: small volume/strong compensation).","Compare vital signs to the age-appropriate normal range, not an adult or generic pediatric reference.","Adapt your communication and exam approach to the child's developmental stage to maximize cooperation and accuracy.","Weigh all findings together (overall gestalt) rather than relying on any single number, especially blood pressure, which is a late sign in pediatric shock."]}]},"c02":{"chapter":"c02","algorithms":[{"id":"c02_alg01","title":"Performing the Pediatric Assessment Triangle","description":"The hands-off, from-the-doorway assessment performed within the first seconds of any pediatric encounter.","steps":["Approach the child without touching; observe from across the room.","Assess Appearance using TICLS: Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry.","Assess Work of Breathing: listen for abnormal sounds (stridor, grunting, wheeze, muffled voice); look for abnormal positioning, retractions, nasal flaring, head bobbing.","Assess Circulation to Skin: look for pallor, mottling, or cyanosis compared to the child's baseline, in adequate lighting.","Combine all three legs into a pattern to identify the likely physiologic category and urgency.","Proceed immediately to the full hands-on primary assessment (ABCDE), paced according to the PAT's urgency level."]},{"id":"c02_alg02","title":"PAT Pattern-to-Category Recognition","description":"Translating the combination of abnormal PAT legs into a likely physiologic category.","steps":["Abnormal Appearance only → likely CNS/metabolic problem.","Abnormal Appearance + Work of Breathing → likely respiratory problem.","Abnormal Appearance + Circulation to Skin → likely shock/circulatory problem.","Abnormal Appearance + Work of Breathing + Circulation to Skin → cardiopulmonary failure (highest urgency).","All three legs normal → reassuring general impression; proceed to primary assessment at a routine pace."]}]},"c03":{"chapter":"c03","algorithms":[{"id":"c03_alg01","title":"Pediatric Primary Assessment (ABCDE) Sequence","description":"The hands-on structured exam following the PAT, with immediate treatment of any life threat found.","steps":["Airway: assess patency; open/clear/manage immediately if compromised.","Breathing: assess rate, effort, breath sounds, SpO2; assist ventilation immediately if inadequate.","Circulation: assess pulse, skin perfusion, capillary refill, external bleeding; control hemorrhage and support perfusion immediately if compromised.","Disability: rapid neurologic check (e.g., AVPU), pupils, glucose if altered.","Exposure: assess for injury/rash as needed, then re-cover to maintain warmth.","Assign overall priority (high vs. low acuity) based on combined PAT + ABCDE findings.","Proceed to secondary assessment (history-taking, focused exam) if priority allows, or continue rapid transport/intervention if high priority."]}]},"c04":{"chapter":"c04","algorithms":[{"id":"c04_alg01","title":"History-Taking and Secondary Assessment Sequence","description":"Gathering history and performing a developmentally appropriate exam after the primary assessment.","steps":["Obtain SAMPLE history, asking the child directly when developmentally appropriate and using the caregiver to supplement.","Add pediatric-specific elements: birth/developmental history (infants), immunizations, growth/weight trends.","Choose exam order by development: toe-to-head for infants/toddlers; head-to-toe for school-age/adolescents.","Perform a focused exam (stable/low-priority) or rapid exam (high-priority, often en route).","Apply family-centered care: keep a calm, cooperative caregiver present and involved where feasible.","Adapt communication for special needs: professional interpretation, hearing-impaired accommodations, developmental-difference considerations.","Integrate findings with the PAT and primary assessment to finalize the treatment and transport plan."]}]},"c05":{"chapter":"c05","algorithms":[{"id":"c05_alg01","title":"Categorizing and Managing Pediatric Respiratory Compromise","description":"Field approach to categorizing a respiratory complaint by mechanism and matching treatment accordingly.","steps":["Complete the PAT and primary assessment to identify a respiratory problem.","Listen and look for the category-defining pattern: stridor (upper airway), wheeze with prolonged expiration (lower airway), grunting/crackles/diminished sounds (lung tissue), or irregular pattern without classic sounds (disordered control).","For upper airway obstruction: keep the child calm, position of comfort with caregiver, minimize agitation, avoid invasive exam of the airway in the field.","For lower airway disease: consider nebulized bronchodilator per local protocol, position of comfort, monitor for fatigue.","For lung tissue disease: supplemental oxygen, position of comfort, monitor closely for hypoxia progression.","For disordered control of breathing: identify and address the underlying cause where possible (e.g., naloxone for suspected opioid exposure per protocol), support ventilation as needed.","Reassess PAT and vital signs frequently for any transition from distress toward failure."]},{"id":"c05_alg02","title":"Recognizing and Responding to Impending Respiratory Failure","description":"Sequence for identifying early warning signs of failure and escalating support before deterioration is severe.","steps":["Reassess a child in respiratory distress at frequent intervals, not just once.","Watch for new or worsening grunting.","Watch for decreasing work of breathing in a child who was previously struggling hard — treat this as a sign of exhaustion, not improvement, until proven otherwise.","Watch for a shift in PAT Appearance from anxious/agitated to lethargic.","Watch for a falling or irregular respiratory rate after a period of tachypnea.","If any of these signs are present, escalate immediately: assist ventilation with BVM and high-flow oxygen, prepare for rapid transport.","Do not wait for SpO2 to fall before escalating support — treat these clinical signs as leading indicators.","For drug-assisted airway management or arrest-specific ventilation parameters, refer to the PALS reviewer."]}]},"c06":{"chapter":"c06","algorithms":[{"id":"c06_alg01","title":"Pediatric Shock Recognition","description":"Sequence for recognizing shock from perfusion findings rather than waiting for hypotension.","steps":["Complete the PAT, noting Appearance and Circulation to Skin.","Assess perfusion directly: capillary refill, skin color/temperature, peripheral pulse quality compared to central pulses, mental status.","Check heart rate for tachycardia out of proportion to fever/anxiety.","Check blood pressure for age — remember normal BP does not exclude shock.","If perfusion findings are abnormal with normal BP: compensated shock — begin treatment now, do not wait for hypotension.","If perfusion findings are abnormal with low BP for age: decompensated shock — treat as a time-critical emergency and escalate immediately.","Reassess perfusion frequently throughout care and transport."]},{"id":"c06_alg02","title":"Category-Matched Shock Treatment","description":"Matching the suspected shock category to the appropriate field intervention.","steps":["Gather history and exam clues to identify the likely shock category: fluid/blood loss (hypovolemic), fever or allergen exposure (distributive), cardiac history (cardiogenic), trauma with unilateral chest findings (obstructive).","Hypovolemic or septic (distributive): administer isotonic fluid bolus per local protocol; reassess perfusion after each bolus.","Anaphylactic (distributive): administer epinephrine as the priority treatment.","Cardiogenic: give fluids cautiously, watching for signs of volume overload; avoid aggressive bolusing.","Obstructive from tension pneumothorax: perform needle decompression per protocol/scope of practice.","In all categories: supplemental oxygen, positioning, keep the child warm, and rapid transport.","For advanced resuscitation and drug dosing depth, refer to the PALS reviewer."]}]},"c07":{"chapter":"c07","algorithms":[{"id":"c07_alg01","title":"Pediatric Bradycardia Field Approach","description":"Sequence for recognizing and initially managing symptomatic pediatric bradycardia in the field.","steps":["Confirm bradycardia for age and assess perfusion (color, capillary refill, mental status).","Assess airway and breathing first — most pediatric bradycardia is caused by hypoxia.","Support oxygenation and ventilation immediately (supplemental oxygen, assisted ventilation if indicated).","Consider other reversible causes if oxygenation/ventilation does not resolve bradycardia: increased vagal tone, hypothermia, increased intracranial pressure.","If bradycardia with poor perfusion persists despite adequate oxygenation and ventilation, this is a time-critical emergency — refer to the PALS reviewer for arrest-level bradycardia algorithms and drug dosing.","Reassess continuously and transport rapidly."]},{"id":"c07_alg02","title":"Distinguishing and Responding to Pediatric Tachycardia","description":"Field approach to differentiating sinus tachycardia from SVT and responding appropriately.","steps":["Identify the heart rate and assess for a clear triggering cause (fever, pain, anxiety, dehydration, shock).","If the rate is variable and a clear trigger is present: treat as sinus tachycardia by addressing the underlying cause (e.g., antipyretics for fever per protocol, fluids for dehydration/shock).","If the rate is fixed, very rapid (often >220 bpm in infants, >180 bpm in older children), and does not vary with stimulation or have a clear trigger: suspect SVT.","For suspected SVT with adequate perfusion: supportive care, monitor closely, rapid transport, notify receiving facility.","For suspected SVT with poor perfusion or altered mental status: this is a time-critical emergency — refer to the PALS reviewer for rhythm-specific interventions (e.g., vagal maneuvers, cardioversion, adenosine dosing).","Reassess frequently during transport."]}]},"c08":{"chapter":"c08","algorithms":[{"id":"c08_alg01","title":"Pediatric Altered Mental Status Field Approach","description":"Sequence for evaluating and managing a child with altered mental status.","steps":["Note Appearance abnormalities on the PAT and confirm level of consciousness using AVPU.","Check blood glucose when a meter is available; treat hypoglycemia per protocol if present.","Work through AEIOU-TIPS to consider reversible causes: Alcohol/substance, Epilepsy/postictal, Infection, Overdose, Uremia/metabolic, Trauma/temperature, Insulin/hypoglycemia, Psychiatric, Shock/stroke.","Assess for signs of increased intracranial pressure: bulging fontanelle, decreasing consciousness, irregular respirations, Cushing triad.","Support airway, breathing, and circulation as needed; avoid hypoxia and hypotension.","Reassess mental status serially and treat a worsening trend as more concerning than any single value.","Transport rapidly with continuous monitoring."]},{"id":"c08_alg02","title":"Pediatric Seizure Field Management","description":"Sequence for managing an actively seizing child and recognizing status epilepticus.","steps":["Protect the airway with positioning and suction as needed; do not place anything in the mouth.","Protect the child from injury during the seizure.","Check blood glucose when available.","Time the seizure from onset.","If the seizure resolves in under 5 minutes and the child returns to baseline, assess for simple vs complex febrile seizure criteria if fever is present, and transport for evaluation.","If the seizure lasts 5 minutes or longer, or seizures repeat without return to baseline, treat as status epilepticus — a time-critical emergency requiring immediate escalation (refer to PALS reviewer for benzodiazepine dosing).","Reassess airway, breathing, and mental status continuously during and after the seizure."]}]}},"tables":{"c01":{"chapter":"c01","tables":[{"id":"c01_t01","title":"Age-Banded Normal Pediatric Vital Signs","headers":["Age Group","Heart Rate (bpm)","Respiratory Rate (breaths/min)","Systolic BP (mmHg)","Hypotension Threshold (SBP)"],"rows":[["Neonate (0–28 days)","100–160","30–60","60–80","< 60 mmHg"],["Infant (1–12 months)","100–160","24–40","70–100","< 70 mmHg"],["Toddler (1–3 years)","90–150","20–30","80–100","< 74 mmHg (70 + 2×2)"],["Preschool (4–5 years)","80–140","20–28","85–110","< 78–80 mmHg (70 + 2×[4–5])"],["School-age (6–12 years)","70–120","18–24","90–120","< 82–94 mmHg (70 + 2×[6–12])"],["Adolescent (13–18 years)","60–100","12–20","100–130","< 90 mmHg (adult threshold)"]]},{"id":"c01_t02","title":"Developmental Stage & Communication Approach","headers":["Stage","Typical Fears/Concerns","Assessment Approach"],"rows":[["Infant (0–12 mo)","Separation from caregiver, hunger, discomfort","Assess largely by observation; keep with caregiver; minimize handling"],["Toddler (1–3 yr)","Separation, strangers, unfamiliar equipment","Keep caregiver close; demonstrate equipment on doll/caregiver first; toe-to-head exam order"],["Preschool (4–5 yr)","Bodily injury, the unknown, magical thinking","Simple honest explanations; allow choices where possible; involve caregiver"],["School-age (6–12 yr)","Loss of control, being different from peers","Direct honest explanation; involve child in decisions; respect modesty"],["Adolescent (13–18 yr)","Privacy, body image, independence","Privacy and respect; consider interviewing partly apart from caregivers; honesty about findings"]]}]},"c02":{"chapter":"c02","tables":[{"id":"c02_t01","title":"Pediatric Assessment Triangle — Legs and Findings","headers":["Leg","Mnemonic/Focus","Normal","Abnormal"],"rows":[["Appearance","TICLS: Tone, Interactiveness, Consolability, Look/Gaze, Speech/Cry","Alert, interactive, consolable, strong cry/speech","Limp, uninterested, inconsolable, weak/absent cry"],["Work of Breathing","Sounds, position, retractions, flaring, head bobbing","Quiet, comfortable position, no retractions","Stridor/grunting/wheeze, tripod position, retractions, flaring, head bobbing"],["Circulation to Skin","Color compared to baseline","Pink, normal color for the child","Pallor, mottling, cyanosis"]]},{"id":"c02_t02","title":"PAT Pattern → Likely Category","headers":["Abnormal Leg(s)","Likely Category","Urgency"],"rows":[["Appearance only","CNS/metabolic problem","Elevated"],["Appearance + Work of Breathing","Respiratory problem","Urgent"],["Appearance + Circulation to Skin","Shock/circulatory problem","Urgent"],["Appearance + Work of Breathing + Circulation to Skin","Cardiopulmonary failure","Highest — immediate action"],["None (all normal)","Reassuring general impression","Routine pace"]]}]},"c03":{"chapter":"c03","tables":[{"id":"c03_t01","title":"Pediatric ABCDE Primary Assessment Components","headers":["Step","What's Assessed","Immediate Action if Abnormal"],"rows":[["Airway","Patency, maintainability","Open/clear/position; adjunct if needed"],["Breathing","Rate, effort, sounds, SpO2","Assist ventilation; supplemental oxygen"],["Circulation","Pulse, perfusion, capillary refill, bleeding","Control hemorrhage; support perfusion"],["Disability","Neuro status (AVPU), pupils, glucose if altered","Treat identified cause (e.g., glucose for hypoglycemia)"],["Exposure","Injury/rash survey","Re-cover promptly to prevent heat loss"]]}]},"c04":{"chapter":"c04","tables":[{"id":"c04_t01","title":"SAMPLE History Components (Pediatric-Adapted)","headers":["Letter","Element","Pediatric Addition"],"rows":[["S","Signs/Symptoms","Ask the child directly when age-appropriate"],["A","Allergies","Include reactions to foods/environmental allergens common in childhood"],["M","Medications","Include dosing by weight where relevant"],["P","Past medical history","Birth history/developmental milestones (infants); immunization status"],["L","Last oral intake","Important for procedural/anesthesia planning"],["E","Events leading up to incident","Include caregiver supervision context where relevant"]]},{"id":"c04_t02","title":"Exam Order by Developmental Stage","headers":["Stage","Preferred Exam Order","Rationale"],"rows":[["Infant/Toddler","Toe-to-head","Less threatening areas first improves cooperation"],["Preschool","Toe-to-head, or head-to-toe with explanation","Some tolerance for direct explanation begins"],["School-age/Adolescent","Standard head-to-toe","Generally cooperative with direct explanation"]]}]},"c05":{"chapter":"c05","tables":[{"id":"c05_t01","title":"Four Categories of Pediatric Respiratory Compromise","headers":["Category","Classic Finding","Example Causes","Field Treatment Focus"],"rows":[["Upper airway obstruction","Stridor","Croup, foreign body, epiglottitis","Keep calm, position of comfort, minimize agitation"],["Lower airway disease","Wheeze, prolonged expiration","Asthma, bronchiolitis","Nebulized bronchodilator per protocol, position of comfort"],["Lung tissue (parenchymal) disease","Grunting, crackles, diminished breath sounds","Pneumonia, pulmonary edema","Supplemental oxygen, close monitoring for hypoxia"],["Disordered control of breathing","Irregular rate/pattern, no classic sound","CNS problem, toxin, neuromuscular disease","Address underlying cause where possible, support ventilation"]]},{"id":"c05_t02","title":"Respiratory Distress vs Respiratory Failure","headers":["Feature","Distress (Compensating)","Failure (Compensation Failed)"],"rows":[["Work of breathing","Increased (retractions, flaring, grunting)","May appear decreased due to exhaustion"],["Mental status","Generally normal/anxious","Altered — lethargic or unresponsive"],["Color","Usually normal or slightly pale","Cyanosis"],["Respiratory rate/pattern","Tachypnea, regular","Bradypnea or irregular, may have apnea"],["Field priority","Position of comfort, O2, targeted treatment, monitor","Assisted ventilation, rapid transport"]]}]},"c06":{"chapter":"c06","tables":[{"id":"c06_t01","title":"Compensated vs Decompensated Shock","headers":["Feature","Compensated Shock","Decompensated Shock"],"rows":[["Blood pressure","Normal for age","Low for age (late finding)"],["Heart rate","Elevated (tachycardia)","Elevated, may become bradycardic terminally"],["Capillary refill","Delayed (>2 sec)","Markedly delayed"],["Mental status","May be normal or mildly irritable","Often altered — lethargic or unresponsive"],["Field urgency","Treat now — do not wait for BP to drop","Time-critical emergency, immediate escalation"]]},{"id":"c06_t02","title":"Categories of Pediatric Shock","headers":["Category","Mechanism","Example Causes","Priority Field Treatment"],"rows":[["Hypovolemic","Fluid/blood volume loss","Dehydration (vomiting/diarrhea), hemorrhage, burns","Isotonic fluid bolus per protocol"],["Distributive","Abnormal vessel tone/permeability","Septic shock, anaphylactic shock, neurogenic shock (rare)","Fluid bolus (septic); epinephrine (anaphylactic)"],["Cardiogenic","Pump failure","Congenital heart disease, myocarditis, arrhythmia","Cautious fluids, avoid volume overload"],["Obstructive","Physical obstruction to blood flow","Tension pneumothorax, cardiac tamponade, massive PE (rare)","Needle decompression (tension pneumothorax) per protocol"]]}]},"c07":{"chapter":"c07","tables":[{"id":"c07_t01","title":"Sinus Tachycardia vs Supraventricular Tachycardia (SVT)","headers":["Feature","Sinus Tachycardia","SVT"],"rows":[["Rate pattern","Variable, changes with stimulation/treatment","Fixed, does not vary with stimulation"],["Typical rate","Rarely exceeds ~220 bpm (infants)","Often >220 bpm (infants), >180 bpm (older children)"],["Trigger","Clear cause: fever, pain, anxiety, dehydration, shock","Often no clear trigger, may be sudden onset"],["Response to treating cause","Resolves as underlying cause is treated","Does not resolve by treating a triggering illness"],["Field approach","Treat underlying cause","Supportive care; refer to PALS for rhythm-specific treatment if poorly perfusing"]]},{"id":"c07_t02","title":"BLS vs ALS Scope of Practice — Pediatric Cardiac Emergencies","headers":["Intervention","BLS Scope","ALS Scope"],"rows":[["Oxygen administration / BVM ventilation","Yes","Yes"],["AED use for pulseless arrest","Yes","Yes"],["Cardiac monitoring / rhythm interpretation","Limited/not typical","Yes"],["IV/IO access","No","Yes"],["Antiarrhythmic medication administration","No","Yes (per PALS protocols)"],["Manual defibrillation / synchronized cardioversion","No","Yes (per PALS protocols)"]]}]},"c08":{"chapter":"c08","tables":[{"id":"c08_t01","title":"AEIOU-TIPS: Reversible Causes of Altered Mental Status","headers":["Letter","Cause"],"rows":[["A","Alcohol/substance use"],["E","Epilepsy/seizure (postictal state)"],["I","Infection"],["O","Overdose/opioids"],["U","Uremia/metabolic derangement"],["T","Trauma/temperature (hyperthermia/hypothermia)"],["I","Insulin/hypoglycemia"],["P","Psychiatric"],["S","Shock/stroke"]]},{"id":"c08_t02","title":"Simple vs Complex Febrile Seizure","headers":["Feature","Simple Febrile Seizure","Complex Febrile Seizure"],"rows":[["Pattern","Generalized","May be focal"],["Duration","Less than 15 minutes","More than 15 minutes"],["Recurrence","Does not recur within 24 hours","May recur within 24 hours"],["Return to baseline","Yes, afterward","May not return promptly to baseline"],["Level of concern","Generally benign","Warrants higher level of concern/evaluation"]]}]}}};
